INSERT INTO public.photos VALUES (23166, 'Estaciâ”œâ”‚n El Portillo 2006', 'Vista aâ”œÂ®rea del entorno de la estaciâ”œâ”‚n El Portillo en 2006, tras su abandono en 2003. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.65209300, -0.89524800, '0101000020E6100000ACE63922DFA5ECBFAB798EC877D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32791228421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32791228421.webp', 'https://www.flickr.com/photos/zaragozaantigua/32791228421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23195, 'Agrupaciâ”œâ”‚n Jubilados RENFE 2010', 'Foto: Rusolera, febrero de 2010. Sede de la Agrupaciâ”œâ”‚n de Pensionistas y Jubilados de RENFE, en la avenida Josâ”œÂ® Anselmo Clavâ”œÂ® de Zaragoza. El mismo aâ”œâ–’o de la foto, este edificio neomudâ”œÂ®jar serâ”œÃ­ derribado. Fuente: zaragozaciudad.net/zaragozafluye/2010/080301-sede-de-la-a...', 2010, 2010, 2010, 'Siglo XXI', 'DELICIAS', 41.65289600, -0.89371300, '0101000020E6100000505260014C99ECBF38D89B1892D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21496097670.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21496097670.webp', 'https://www.flickr.com/photos/zaragozaantigua/21496097670/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23220, 'Derribo Averly 2016', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 17 de la calle del Trovador durante el derribo de la veterana y referencial fundiciâ”œâ”‚n Averly que, activa desde 1880 y hasta 2011, fue demolida en 2/3 de su original extensiâ”œâ”‚n para dar paso, con el beneplâ”œÃ­cito de los poderes econâ”œâ”‚micos de la ciudad, a una necesaria promociâ”œâ”‚n privada de 120 viviendas de lujo de la constructora Brial cuya ejecuciâ”œâ”‚n comenzarâ”œÃ­ a principios de 2021, y cuyas llaves se entregarâ”œÃ­n en 2022-2023. Al fondo, entorno de la antigua estaciâ”œâ”‚n de Zaragoza-El Portillo.', 2016, 2016, 2016, 'Siglo XXI', 'DELICIAS', 41.65447200, -0.89510600, '0101000020E61000000E828E56B5A4ECBFE8120EBDC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50678763063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50678763063.webp', 'https://www.flickr.com/photos/zaragozaantigua/50678763063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23234, 'Cuartel del Cid 2021', 'El cuartel de Caballerâ”œÂ¡a del Portillo, llamado luego del Cid, fue levantado en 1775 a instancias de Ramâ”œâ”‚n Pignatelli, segâ”œâ•‘n proyecto de Pedro Pablo Camâ”œâ”‚n. Se alzâ”œâ”‚ en el solar ocupado desde 1766 como Ã”Ã‡Â£tinglado de artillerâ”œÂ¡aÃ”Ã‡Ã˜ (polvorâ”œÂ¡n y armerâ”œÂ¡a), junto al convento de los Agustinos Descalzos (1602), derruido en los Sitios de 1808-1809 y cuyos terrenos sirvieron para ampliar el cuartel. Entre 1968 y 1976 fue derribado, conservando su tapia recayente al paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. En 2021 se realizaron prospecciones arqueolâ”œâ”‚gicas con miras a construir viviendas en el solar, y aparecieron viviendas islâ”œÃ­micas, estructuras medievales y restos del cuartel. Una vez arrasado todo con la autorizaciâ”œâ”‚n de la comisiâ”œâ”‚n de Patrimonio del Gobierno de Aragâ”œâ”‚n, en 2022 se comienza la construcciâ”œâ”‚n allâ”œÂ¡ de una urbanizaciâ”œâ”‚n de lujo, conservando parte del muro y la puerta trasera del recinto militar. En la foto, vista del yacimiento arqueolâ”œâ”‚gico en agosto de 2021, con el Edificio Pignatelli y el de la Maternidad al fondo. A la derecha, fuera de plano, el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n.', 2021, 2021, 2021, 'Siglo XXI', 'DELICIAS', 41.65422300, -0.89269200, '0101000020E61000009ED32CD0EE90ECBF40A54A94BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51868764065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51868764065.webp', 'https://www.flickr.com/photos/zaragozaantigua/51868764065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23271, 'Campo del Sepulcro 1808', '"Batalla de las Heras, en la cual los franceses, intentando forzar el punto de Buena Vista y penetrar en Zaragoza fueron rechazados gloriosamente por los Aragoneses, y forzados a situarse fuera del tiro de caâ”œâ–’â”œâ”‚n de la Ciudad", Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. La batalla de las Eras (una zona agrâ”œÂ¡cola de la periferia de la ciudad), o del Campo del Sepulcro, tuvo lugar el 15 de junio de 1808, donde dâ”œÂ®cadas despuâ”œÂ®s se levantarâ”œÂ¡a la Estaciâ”œâ”‚n de Ferrocarril del mismo nombre (Campo Sepulcro). De resultas del combate, los soldados franceses no tuvieron â”œÂ®xito en su ataque, y se retiraron. Al fondo, se eleva el castillo de La Aljaferâ”œÂ¡a. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65251400, -0.89476300, '0101000020E61000009677D503E6A1ECBF5017299485D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15266672542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15266672542.webp', 'https://www.flickr.com/photos/zaragozaantigua/15266672542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23316, 'Campo Sepulcro c.1912', 'La apertura de la lâ”œÂ¡nea Zaragoza-Madrid el 25 de mayo de 1863 supuso la inauguraciâ”œâ”‚n de la estaciâ”œâ”‚n de Campo Sepulcro, recinto provisional que acogiâ”œâ”‚ los primeros viajeros de la lâ”œÂ¡nea Madrid-Zaragoza-Alicante (MZA). En 1896 se inaugurâ”œâ”‚ la estaciâ”œâ”‚n definitiva, proyectada con aires clasicistas por el ingeniero Lâ”œâ”‚pez de Letona, con su larga fachada de 144 metros de longitud de la que sobresale en planta y altura un gran pabellâ”œâ”‚n central, que en la imagen centra la escena, acompaâ”œâ–’ado de dos pabellones algo mâ”œÃ­s pequeâ”œâ–’os en los extremos hasta los que se dispone una marquesina corrida para proteger de la solanera canicular. La parte metâ”œÃ­lica de su estructura provenâ”œÂ¡a de los cercanos talleres Averly, salvo la armadura de vigas de la cubierta, que era bilbaâ”œÂ¡na, y los ladrillos y tejas de los tejares locales. Un acabado final mâ”œÃ­s que digno, por encima de la media de otras estaciones peninsulares y aun europeas. En 1967, tras el cierre de las estaciones de Cariâ”œâ–’ena, Utrillas y Caminreal pasâ”œâ”‚ a ser la principal estaciâ”œâ”‚n de la ciudad. En 1973, el ente gestor RENFE procediâ”œâ”‚ a su "ampliaciâ”œâ”‚n y reforma", es decir, a su derribo integral, sustituyâ”œÂ®ndola por otra estaciâ”œâ”‚n moderna y de nueva planta, y cambiando su denominaciâ”œâ”‚n por la de Zaragoza-El Portillo (aunque estaba proyectado que se llamara "de Goya"), hasta que en 2003 fue a su vez sustituida por la actual estaciâ”œâ”‚n de Zaragoza-Delicias. En la imagen, vista de la fachada principal de la estaciâ”œâ”‚n MZA de Campo Sepulcro y su explanada de ingreso desde el paseo de las Estaciones por donde circulaba el tranvâ”œÂ¡a de la lâ”œÂ¡nea de Madrid, que la conectaba con la plaza de la Constituciâ”œâ”‚n.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65216800, -0.89483300, '0101000020E6100000CE35CCD078A2ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14781246727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14781246727.webp', 'https://www.flickr.com/photos/zaragozaantigua/14781246727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23319, 'Fundiciâ”œâ”‚n Averly c.1900', 'Mudados desde la calle San Miguel en 1880 a una nueva ubicaciâ”œâ”‚n mâ”œÃ­s espaciosa en Campo Sepulcro, junto a la homâ”œâ”‚nima estaciâ”œâ”‚n de ferrocarril, Averly inicia una etapa de crecimiento y producciâ”œâ”‚n de raâ”œÂ¡les para tranvâ”œÂ¡as, turbinas hidrâ”œÃ­ulicas, engranajes, poleas, cojinetes, elementos de transmisiâ”œâ”‚n, ruedas dentadas, material sanitario especializado, maquinaria e instalaciones de molinerâ”œÂ¡a, panaderâ”œÂ¡a, extracciâ”œâ”‚n de aceites y vinos, generadores y autoclaves de vapor, instalaciones para riegos y material para la agricultura, etc. En la ciudad, y en el terreno de la fundiciâ”œâ”‚n artâ”œÂ¡stica, reconocemos obras de Averly en la estatua del Justicia (Plaza de Aragâ”œâ”‚n), el leâ”œâ”‚n del Batallador (Cabezo de Buena Vista), la Fuente de la Samaritana (Plaza del Justicia), la Fuente de las Garzas (Plaza de Utrillas), ornamentos de La Seo y El Pilar, los chapiteles de sus torres, las columnas de los porches del Mercado Central, las estructuras metâ”œÃ­licas en los palcos del Teatro Principal... En la imagen, salida de obreros de la fundiciâ”œâ”‚n, porque Averly tambiâ”œÂ®n fue cantera del movimiento obrero organizado en la ciudad. Fuente visual: Archivo Averly.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65443700, -0.89371200, '0101000020E6100000395E81E84999ECBF6C257497C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14787924160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14787924160.webp', 'https://www.flickr.com/photos/zaragozaantigua/14787924160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23320, 'Campo Sepulcro. Proyecto 1896', 'Alzado del proyecto de la estaciâ”œâ”‚n ferroviaria "definitiva" de Zaragoza, denominada de Campo Sepulcro.', 1896, 1896, 1896, 'Siglo XIX', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14856811727.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14856811727.webp', 'https://www.flickr.com/photos/zaragozaantigua/14856811727/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23321, 'Estaciâ”œâ”‚n Campo Sepulcro 1960', 'Antigua estaciâ”œâ”‚n de Madrid. 1960. La estrecha calle de la izquierda separa el conjunto de la estaciâ”œâ”‚n de la fâ”œÃ­brica Escoriaza.', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65366200, -0.89650000, '0101000020E6100000E3A59BC420B0ECBFA8514832ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14933958096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14933958096.webp', 'https://www.flickr.com/photos/zaragozaantigua/14933958096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23326, 'Campo Sepulcro c.1967', 'Imagen del edificio principal de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro o Madrid. Al fondo, a la derecha, los modernos y verticales bloques esquineros entre las calles del Tenor Gayarre, y Manuel Escoriaza y Fabro, e inmediatos a Viasa, y Alsoviasa.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15845267499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15845267499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15845267499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23328, 'Fundiciâ”œâ”‚n Averly c.1903', 'Dibujo de las instalaciones de la fâ”œÃ­brica de fundiciones Averly de Zaragoza, en el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n nâ”¬â•‘ 59. Empresa fundada en 1880. Fuente visual: Gente de orden, Ibercaja, 1997.', 1903, 1903, 1903, 'Anos 1900', 'DELICIAS', 41.65443700, -0.89371200, '0101000020E6100000395E81E84999ECBF6C257497C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20185724960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20185724960.webp', 'https://www.flickr.com/photos/zaragozaantigua/20185724960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23330, 'Campo Sepulcro 1895', 'Fototipia Lucas Escolâ”œÃ­, 1895. Construcciâ”œâ”‚n de la definitiva Estaciâ”œâ”‚n de Campo Sepulcro, o de los Directos, de la lâ”œÂ¡nea MZA (durante casi 29 aâ”œâ–’os hubo una provisional estaciâ”œâ”‚n, unas decenas de metros mâ”œÃ­s al norte, donde los talleres). Serâ”œÃ­ inaugurada en 1896. La imagen estâ”œÃ­ capturada desde el Camino de Herederos, junto a una torre agrâ”œÂ¡cola donde casi 20 aâ”œâ–’os despuâ”œÂ®s serâ”œÃ­ construida la fâ”œÃ­brica de chocolates Ã”Ã‡Â£Casa Orâ”œâ•‘sÃ”Ã‡Ã˜. Fuente visual: www.facebook.com/photo.php?fbid=879415128747780&set=g...', 1895, 1895, 1895, 'Siglo XIX', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20973707464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20973707464.webp', 'https://www.flickr.com/photos/zaragozaantigua/20973707464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23331, 'Campo Sepulcro 1849', '"Plano del Campo del Sepulcro en Zaragoza con el amojonamiento del terreno propio del ramo de guerra, segâ”œâ•‘n las escrituras de venta que obran en el archivo de la Direcciâ”œâ”‚n Subinspecciâ”œâ”‚n de Ingenieros", Joaquâ”œÂ¡n Gironza, Zaragoza, 28 de junio de 1849. Lâ”œÂ¡mites de la propiedad militar del Campo del Sepulcro de Zaragoza, entre el camino de la Casa Blanca (actual avenida Anselmo Clavâ”œÂ®) y el camino de Ronda (actual paseo de Marâ”œÂ¡a Agustâ”œÂ¡n). Fuente: AMZ.', 1849, 1849, 1849, 'Siglo XIX', 'DELICIAS', 41.65283200, -0.89287600, '0101000020E6100000F6436CB07092ECBF21E4BCFF8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21036546012.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21036546012.webp', 'https://www.flickr.com/photos/zaragozaantigua/21036546012/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23332, 'Campo Sepulcro 1961', 'Vâ”œÂ¡as de trâ”œÃ­nsito y convoy estacionado junto a la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro. Al fondo, a la derecha, Anselmo Clavâ”œÂ® y una parcial vista del antiguo edificio de la Casa de Convalecientes, que desde finales de los aâ”œâ–’os cincuenta estaba ocupado por el Colegio Politâ”œÂ®cnico Nuestra Seâ”œâ–’ora del Pilar. Fuente visual: Trevor Rowe, Archivo EuskoTren/Museo Vasco del Ferrocarril.', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23633262179.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23633262179.webp', 'https://www.flickr.com/photos/zaragozaantigua/23633262179/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23334, 'Averly 1909', 'La fundiciâ”œâ”‚n de Antonio Averly llevaba desde 1880 instalada en la industrial zona de Campo Sepulcro, inmediata a la estaciâ”œâ”‚n de ferrocarril de ese nombre. En 1903, la empresa pasâ”œâ”‚ a denominarse "Hijos de A. Averly", y desde 1918, "Averly, S.A." De acuerdo con la teorâ”œÂ¡a microbiana del contagio, las medidas de profilaxis frente a la transmisiâ”œâ”‚n de enfermedades infecciosas se convirtieron en los albores del siglo XX en uno de los pilares bâ”œÃ­sicos de la moderna actuaciâ”œâ”‚n sanitaria. Y aplicar la desinfecciâ”œâ”‚n requiriâ”œâ”‚ nuevos equipos y materiales acordes, que en Averly pronto estuvieron prestos a fabricar y ofrecer al mercado. De esta forma, los grandes talleres de fundiciâ”œâ”‚n y construcciâ”œâ”‚n general de mâ”œÃ­quinas Averly, incluyeron en su catâ”œÃ­logo, y dentro de la categorâ”œÂ¡a "material sanitario", una extensa relaciâ”œâ”‚n de ofertas: estufas fijas y mâ”œâ”‚viles de desinfecciâ”œâ”‚n, pulverizadores, generadores de vapor-formol, esterilizadores, legiadoras, desinfectadoras, carros de transporte... Estos productos estaban destinados a hospitales, lazaretos, sanatorios, lavaderos, penitenciarâ”œÂ¡as, colegios... y Averly atendâ”œÂ¡a a cualquier solicitud de informaciâ”œâ”‚n, o de presupuesto, desde el apartado postal nâ”¬â•‘ 36, y el telâ”œÂ®fono nâ”¬â•‘ 49. En la imagen, un "generador de vapor formol" de tracciâ”œâ”‚n animal construido de Averly, para desinfecciâ”œâ”‚n de todo tipo de tejidos (mantas, colchones, ropa...) mediante la inyecciâ”œâ”‚n de agua con formol a mâ”œÃ­s de 110 grados centâ”œÂ¡grados, durante unos 15 minutos. Fuente visual: Revista "El Monitor Sanitario", Madrid.', 1909, 1909, 1909, 'Anos 1900', 'DELICIAS', 41.65435000, -0.89404300, '0101000020E6100000A1F7C610009CECBF9D11A5BDC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28020637115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28020637115.webp', 'https://www.flickr.com/photos/zaragozaantigua/28020637115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23336, 'Campo Sepulcro 1963', 'Imagen de una locomotora a vapor, posiblemente de la serie "1400", pasando frente al andâ”œÂ®n principal de la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro, en direcciâ”œâ”‚n sur, hacia Miraflores. Detrâ”œÃ­s de ella, el muro perimetral de las enormes instalaciones de la empresa Carde y Escoriaza y, a la izquierda, fuera de plano, la vâ”œÂ¡a de conexiâ”œâ”‚n por donde salâ”œÂ¡a el material rodante allâ”œÂ¡ fabricado. Fuente visual: es.slideshare.net/', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65167300, -0.89558800, '0101000020E6100000E014562AA8A8ECBFD65757056AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30684647422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30684647422.webp', 'https://www.flickr.com/photos/zaragozaantigua/30684647422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23337, 'Campo Sepulcro 1963', 'Imagen de una locomotora a vapor de la MZA, serie 741/780, construida en el Primer Reich alemâ”œÃ­n durante la primera dâ”œÂ®cada del siglo, tirando de un convoy en direcciâ”œâ”‚n a Madrid, delante de las naves y muelles cubiertos localizados en la manzana con forma de quesito entre la calle del Trovador (derecha), y la avenida de Madrid (izquierda). Esta fachada luego serâ”œÂ¡a completamente reedificada de nueva planta, con altos bloques de edificios. A la derecha de la imagen, fuera de plano, se encontraba la amplia zona de muelles de Campo Sepulcro. Fuente visual: image.slidesharecdn.com/', 1963, 1963, 1963, 'Anos 60', 'DELICIAS', 41.65463100, -0.89663900, '0101000020E61000003C2EAA4544B1ECBF51F9D7F2CAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30737601581.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30737601581.webp', 'https://www.flickr.com/photos/zaragozaantigua/30737601581/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23338, 'Estaciâ”œâ”‚n de Madrid 1965', 'Foto: Juliâ”œÃ­n Beguerâ”œÂ¡a Cervero. Acceso a la estaciâ”œâ”‚n de Madrid o Campo Sepulcro, desde la avenida de Josâ”œÂ® Anselmo Clavâ”œÂ® (a la espalda del fotâ”œâ”‚grafo). El niâ”œâ–’o se llama Javier Tregâ”œâ”‚n. A la estaciâ”œâ”‚n le quedaban siete aâ”œâ–’os. Fuente: Heraldo de Aragâ”œâ”‚n.', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65234100, -0.89489400, '0101000020E6100000395FECBDF8A2ECBF836BEEE87FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31582125454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31582125454.webp', 'https://www.flickr.com/photos/zaragozaantigua/31582125454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23339, 'Campo Sepulcro c.1900', 'La fundiciâ”œâ”‚n Averly en su ubicaciâ”œâ”‚n de Campo Sepulcro, cercana al ferrocarril de la lâ”œÂ¡nea MZA, en una imagen capturada frente a su entrada principal desde la "travesâ”œÂ¡a" de la carretera de Madrid a Francia, luego redenominada paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, donde ademâ”œÃ­s estaba ubicada la zona de vivienda fabril, con su correspondiente y ajardinado hotelito, en primer plano. Al fondo, y a la derecha, la zona productiva, con la fundiciâ”œâ”‚n, taller de maquinaria, y almacâ”œÂ®n de modelos-carpinterâ”œÂ¡a. Fuente visual: "Andalâ”œÃ­n, periâ”œâ”‚dico quincenal aragonâ”œÂ®s".', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65432600, -0.89364600, '0101000020E61000005D70067FBF98ECBF147651F4C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31877248433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31877248433.webp', 'https://www.flickr.com/photos/zaragozaantigua/31877248433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23341, 'Estaciâ”œâ”‚n Campo Sepulcro 1908', 'Carroza del rey Alfonso XIII ante la estaciâ”œâ”‚n de Campo Sepulcro, durante su visita en 1908. Fuente: Heraldo de Aragâ”œâ”‚n.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65216500, -0.89502900, '0101000020E610000037177FDB13A4ECBF444C89247AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32430948433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32430948433.webp', 'https://www.flickr.com/photos/zaragozaantigua/32430948433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23342, 'Estatua del Justicia 1899', 'Estatua del Justicia Juan de Lanuza, para el monumento diseâ”œâ–’ado por Fâ”œÂ®lix Navarro, fundida en Averly. Estâ”œÃ­ a la espera de que se coloque en 1904 en la glorieta de Pignatelli, que serâ”œÃ­ entonces redenominada plaza de Aragâ”œâ”‚n. Fuente: Revista Nuevo Mundo, 1899.', 1899, 1899, 1899, 'Siglo XIX', 'DELICIAS', 41.65435000, -0.89404300, '0101000020E6100000A1F7C610009CECBF9D11A5BDC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32697415680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32697415680.webp', 'https://www.flickr.com/photos/zaragozaantigua/32697415680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23343, 'Campo Sepulcro 1908', 'Vista del Campo Sepulcro en 1908, con las tropas formadas durante la visita de Alfonso XIII. Al fondo el cuartel de los Trinitarios (antiguo convento) y la gran torre cuadrangular de la facultad de Medicina y Ciencias. A la izquierda, paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. Abajo, vâ”œÂ¡as del tranvâ”œÂ¡a a la estaciâ”œâ”‚n de Cariâ”œâ–’ena, en la actual avenida de Josâ”œÂ® Anselmo Clavâ”œÂ®. Fuente visual: revista "Ilustraciâ”œâ”‚n militar. Ejâ”œÂ®rcito y Marina".', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65280300, -0.89290000, '0101000020E610000018265305A392ECBF87DD770C8FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33203571146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33203571146.webp', 'https://www.flickr.com/photos/zaragozaantigua/33203571146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23344, 'Campo Sepulcro c.1896', 'Imagen de la nueva estaciâ”œâ”‚n de los Directos en Campo Sepulcro, o estaciâ”œâ”‚n de Madrid, con detalle del inmediato espacio, a la derecha, donde estaba prevista la construcciâ”œâ”‚n del depâ”œâ”‚sito de locomotoras a vapor. A la izquierda, tras el mar de vâ”œÂ¡as, algunas de las Torres del camino de Herederos, al norte del barrio de Cariâ”œâ–’ena. Fuente visual: Guâ”œÂ¡a de Zaragoza 1902.', 1896, 1896, 1896, 'Siglo XIX', 'DELICIAS', 41.65221000, -0.89485300, '0101000020E6100000954737C2A2A2ECBFE40F069E7BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34458892294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34458892294.webp', 'https://www.flickr.com/photos/zaragozaantigua/34458892294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23346, 'Campo Sepulcro 1966', 'Imagen centrada en el paso por el mar de vâ”œÂ¡as de la estaciâ”œâ”‚n Zaragoza-Campo Sepulcro de la moderna locomotora diesel, primera de la serie 352 de las "Vâ”œÂ¡rgenes" y denominada "Virgen del Rosario", tirando de una rama del Talgo III en direcciâ”œâ”‚n a la condal Barcelona. La vistosa combinaciâ”œâ”‚n de los colores rojo y plata en esta composiciâ”œâ”‚n, dicen que constituâ”œÂ¡a todo un espectâ”œÃ­culo para la vista. En 2002 esta locomotora fue dada de baja del servicio, y desguazada, y parece ser que la cabina perdura en el Museo del Ferrocarril de Arganda del Rey, porque los museos del ferrocarril, haberlos haylos. A la izquierda, naves del complejo fabril de Material Mâ”œâ”‚vil y Construcciones. En el centro, la veterana estaciâ”œâ”‚n, con un convoy estacionado y tirado, posiblemente, por una locomotora vaporosa de la serie 401/414. A la derecha e inmediata, aunque fuera de plano, el depâ”œâ”‚sito de locomotoras de vapor. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65147300, -0.89538400, '0101000020E6100000C092AB58FCA6ECBF0F9D9E7763D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39801337703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39801337703.webp', 'https://www.flickr.com/photos/zaragozaantigua/39801337703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23348, 'Campo Sepulcro 1968', 'Ferroviaria estampa capturada en la estaciâ”œâ”‚n de Zaragoza-Campo Sepulcro, cuyo edificio y andâ”œÂ®n principal queda a la izquierda. Centra la imagen un convoy de pasajeros tirado por una locomotora a vapor Mikado, y encaminado en direcciâ”œâ”‚n a Logroâ”œâ–’o. Hacia el fondo destacan las dos torrecillas de Industrias del Cartonaje S.A., antigua fâ”œÃ­brica de chocolates Orâ”œâ•‘s, y algunos de los modernos bloques levantados en el entorno de la moderna avenida de Goya. A la derecha, naves del complejo fabril de Material Mâ”œâ”‚vil y Construcciones. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65147300, -0.89538400, '0101000020E6100000C092AB58FCA6ECBF0F9D9E7763D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46962853502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46962853502.webp', 'https://www.flickr.com/photos/zaragozaantigua/46962853502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23349, 'Campo Sepulcro 1910', 'Imagen capturada en el campo de balompiâ”œÂ® habilitado en Campo Sepulcro y centrada en el "primer team" de la nueva sociedad "Zaragoza Foot-Ball Club", constituida a principios de aâ”œâ–’o y que utlizaba el referido campo para jugar sus partidos. El nombre de "Foot-Ball Club" era habitual entre los equipos pioneros de este deporte en las diversas ciudades donde fueron surgiendo, como el que fue constituido con ese nombre en 1903, que es considerado el primer club local de esta disciplina deportiva en Zaragoza, si bien su vida activa finalizâ”œâ”‚ en 1904. En 1910 surgiâ”œâ”‚ una nueva sociedad que incorporâ”œâ”‚ "Zaragoza" al nombre de aquella "Foot-Ball Club", si bien mantuvo su carâ”œÃ­cter "amateur" y, a la postre, efâ”œÂ¡mero. En 1912 este equipo llegâ”œâ”‚ a inaugurar su propio terreno de juego en el perifâ”œÂ®rico camino de San Josâ”œÂ®, cedido temporalmente por su propietario, el comerciante Francisco Agelet, si bien terminâ”œâ”‚ sus dâ”œÂ¡as jugando en el "campo de los alemanes" de la calle de Bilbao.', 1910, 1910, 1910, 'Anos 10', 'DELICIAS', 41.65116600, -0.89268200, '0101000020E6100000BA4A77D7D990ECBF3222516859D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53461103455.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53461103455.webp', 'https://www.flickr.com/photos/zaragozaantigua/53461103455/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23350, 'Campo Sepulcro 1967', 'Imagen capturada ante el puente giratorio del depâ”œâ”‚sito de locomotoras sito en la estaciâ”œâ”‚n de Zaragoza-Campo Sepulcro, y centrada en un agostino intercambio ferroviario de pareceres, con el fondo de dos vaporosas Renfe 141 o "Mikado" y una Renfe 2701.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65125400, -0.89416200, '0101000020E6100000336E6AA0F99CECBFD1B1834A5CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54226615682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54226615682.webp', 'https://www.flickr.com/photos/zaragozaantigua/54226615682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23694, 'Sanatorio San Jorge 1966', 'En 1920 el arquitecto Miguel â”œÃ¼ngel Navarro diseâ”œâ–’â”œâ”‚ una vivienda para la familia Monterde en la calle Marcelino Domingo (Padre Manjâ”œâ”‚n, tras el 18 de julio de 1936) del Barrio de la Explanada, muy cerca del enlace del ferrocarril de Cariâ”œâ–’ena con la estaciâ”œâ”‚n de Campo Sepulcro. El edificio estaba definido en un estilo neorregionalista que incorporaba elementos del repertorio modernista. Mâ”œÃ­s tarde fue bastante modificado y ampliado, segâ”œâ•‘n los distintos usos que se le fueron dando. En la abrileâ”œâ–’a imagen, el edificio funcionando como "Sanatorio S. Jorge. Obra Sindical 18 de Julio". Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65341000, -0.90171500, '0101000020E610000026016A6AD9DAECBF8F705AF0A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15217731081.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15217731081.webp', 'https://www.flickr.com/photos/zaragozaantigua/15217731081/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23644, '&quot;Feliz Navidad&quot; 1938', 'En fechas seâ”œâ–’aladamente entraâ”œâ–’ables, una oximorâ”œâ”‚nica estampa navideâ”œâ–’a con uno los soldados alemanes de la Luftwaffe encuadrados en la denominada "Legiâ”œâ”‚n Câ”œâ”‚ndor", durante su destino en el Aerâ”œâ”‚dromo de Sanjurjo de la ciudad, cuando funcionaba como base aâ”œÂ®rea de utilizaciâ”œâ”‚n conjunta, en este caso hispano-germano-italiana, desde 1937. "Feliz Navidad" ("Frohe Weihnachten"), y algo parecido al trazo de unos cristales de nieve, iluminan y llenan de sentimiento el posado junto a dos, entre otros proyectiles de menor calibre, impactantes artefactos explosivos de bombardeo empleados por la fuerza aâ”œÂ®rea nazi destacada en apoyo de la Espaâ”œâ–’a nacionalista.', 1938, 1938, 1938, 'Anos 30', NULL, 41.66303700, -1.02413100, '0101000020E6100000CD1DFD2FD762F0BFDC847B65DED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15811716717.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15811716717.webp', 'https://www.flickr.com/photos/zaragozaantigua/15811716717/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23709, 'Calle de Graus 1932', 'Imagen de la parcela del nâ”¬â•‘ 6 de la calle Graus, en el barrio de las Delicias, donde fueron detenidas cuatro personas por posesiâ”œâ”‚n de metralla y componentes quâ”œÂ¡micos (clorato de potasa, glicerina, azufre, â”œÃ­cido sulfâ”œâ•‘rico...) susceptibles de ser utilizados para fabricar bombas y explosivos. Los detenidos fueron puestos a disposiciâ”œâ”‚n judicial. La parcela-polvorâ”œÂ¡n estaba ubicada muy cerca de la calle de Unceta, y casi frente al solar donde dos aâ”œâ–’os mâ”œÃ­s tarde los escolapios construirâ”œÂ¡an la primera iglesia parroquial de San Valero, que tambiâ”œÂ®n contaba con un local para escuelas, que llegâ”œâ”‚ a albergar a 80 alumnos. Iglesia y escuela estuvieron activas hasta 1939, en que cerraron. Una nueva iglesia parroquial de San Valero se levantarâ”œÂ¡a en los aâ”œâ–’os 40, y buena parte de su mobiliario procedâ”œÂ¡a de la derribada iglesia de San Andrâ”œÂ®s Apâ”œâ”‚stol. Fuente visual: Foto Martâ”œÂ¡nez ("Mundo Grâ”œÃ­fico", Madrid).', 1932, 1932, 1932, 'Anos 30', 'DELICIAS', 41.65257900, -0.90268000, '0101000020E6100000DF1AD82AC1E2ECBF38876BB587D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21440630243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21440630243.webp', 'https://www.flickr.com/photos/zaragozaantigua/21440630243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23717, 'Av. de Madrid 1976', 'Imagen capturada en la avenida de Madrid junto al cine Madrid (izquierda), inaugurado en 1955 con proyecto del arquitecto Eduardo Lagunilla. Este cine fue clausurado unos aâ”œâ–’os mâ”œÃ­s tarde, en 1984, y el amplio local reconvertido en centro de fomento de la ludopatâ”œÂ¡a. A la derecha, irrepetible imagen de la antigua fachada de los nâ”œâ•‘meros pares de la avenida desde el nâ”œâ•‘mero 36 hasta la calle del Arzobispo Aâ”œâ–’oa de Busto, cuyo moderno nâ”œâ•‘mero 1 (antiguo 44 de la avenida) estâ”œÃ­ en pleno proceso de descontextualizada construcciâ”œâ”‚n, al uso de la â”œÂ®poca. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.65413400, -0.90177800, '0101000020E6100000BE1248895DDBECBFD099B4A9BAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27802236399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27802236399.webp', 'https://www.flickr.com/photos/zaragozaantigua/27802236399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21509, 'Cabezo de Buena Vista c.1926', 'Patrimonio Cultural Universidad de Zaragoza. Luis Gandâ”œâ•‘ Mercadal. Ca. 1926. Paseo por Cabezo de Buena Vista una fresca maâ”œâ–’ana de invierno. En la imagen, Mâ”¬Â¬ Luisa Gandâ”œâ•‘ Dorel, hija de Luis Gandâ”œâ•‘ Mercadal. Detrâ”œÃ­s de ellas, la ciudad de Zaragoza vista desde este Cabezo. Fuente visual: patrimoniocultural.unizar.es/node/3153', 1926, 1926, 1926, 'Anos 20', 'UNIVERSIDAD', 41.63246000, -0.89215300, '0101000020E6100000BCE7C072848CECBF9B030473F4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15649014151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15649014151.webp', 'https://www.flickr.com/photos/zaragozaantigua/15649014151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23729, 'Av. de Madrid 1979', 'Imagen del incuestionable absolutismo del motor en la â”œÂ®poca, tramo de la avenida de Madrid justo al lado del despartidero (a la derecha) que mojoneaba el arranque de la avenida de Navarra, y que se mantenâ”œÂ¡a como barbecho urbanâ”œÂ¡stico usufructuado mientras tanto por comerciales diversos, incluyendo propaganda electoral del Partido del Trabajo de Aragâ”œâ”‚n, ilustrada con la imagen de su candidato cabecero a las Elecciones Generales de 1979, el secretario general de la Confederaciâ”œâ”‚n de Sindicatos Unitarios de Trabajadores, CSUT , Jerâ”œâ”‚nimo Lorente Hernâ”œÃ­ndez. A la izquierda, imagen del antiguo nâ”¬â•‘ 117 de la avenida, luego sustituido por un moderno bloque hasta cuatro veces mâ”œÃ­s alto. Fuente visual: Banco de Imâ”œÃ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œÂ®, amablemente cedida para el', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65439600, -0.90136100, '0101000020E6100000B3791C06F3D7ECBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33191005256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33191005256.webp', 'https://www.flickr.com/photos/zaragozaantigua/33191005256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23731, 'Delicias c.1925', 'Imagen capturada desde la altura de la fâ”œÃ­brica de Carde y Escoriaza inmediata a la estaciâ”œâ”‚n ferroviaria de Campo Sepulcro, orientada hacia el oeste, con una interesante panorâ”œÃ­mica de la barriada de las Delicias. En primer tâ”œÂ®rmino, y tras el ramal del Boquerazo de la acequia de la Romareda, antiguos campos de Tarongi y de la Torre de Domingo. En el centro de la imagen, el referencial remate que culminaba la casa de la familia Monterde en la calle de Marcelino Domingo. Al fondo a la izquierda, la casa de la familia Palomar destaca desde su dominante emplazamiento natural. Fuente visual: Archivo CAF (AHPZ-DARA)', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65305400, -0.90008200, '0101000020E610000016FC36C478CDECBFD042024697D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37768583714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37768583714.webp', 'https://www.flickr.com/photos/zaragozaantigua/37768583714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23733, 'Calle del Padre Manjâ”œâ”‚n 1980', 'En 1920 el arquitecto Miguel â”œÃ¼ngel Navarro diseâ”œâ–’â”œâ”‚ una destacada vivienda para la familia Monterde en la calle Marcelino Domingo (redenominada del Padre Andrâ”œÂ®s Manjâ”œâ”‚n, tras el 18 de julio de 1936) del barrio de la Explanada, muy cerca del enlace del ferrocarril de Cariâ”œâ–’ena con la estaciâ”œâ”‚n de Campo Sepulcro. Este edificio estaba definido en un estilo neorregionalista que incorporaba elementos del repertorio modernista. Mâ”œÃ­s tarde fue bastante modificado y ampliado, segâ”œâ•‘n los distintos usos que se le fueron dando con el paso del tiempo. En la imagen, el inmueble funcionando como "Clâ”œÂ¡nica San Jorge de la SS (Seguridad Social)" del Instituto Nacional de la Salud (INSALUD), heredero del previo Instituto Nacional de Previsiâ”œâ”‚n. Fuente visual: AMZ', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65341000, -0.90171500, '0101000020E610000026016A6AD9DAECBF8F705AF0A2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41283023180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41283023180.webp', 'https://www.flickr.com/photos/zaragozaantigua/41283023180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23922, 'Cuartel de El Cid 1968', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1968. Imagen del interior de los patios del antiguo Cuartel de Caballerâ”œÂ¡a de El Cid, tras el derribo de sus instalaciones. Al fondo, a la izquierda, la Iglesia de El Portillo, y las traseras de algunas viviendas de la plaza. A la derecha, sobresale levemente la torre-câ”œâ•‘pula de la sucursal de una entidad bancaria local. Una buena parte de los solares resultantes siguen a la espera de un destino urbanizado.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65435600, -0.89290700, '0101000020E6100000B7D26BB3B192ECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15030027708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15030027708.webp', 'https://www.flickr.com/photos/zaragozaantigua/15030027708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23932, 'Cuartel del Cid 1968', 'Imagen capturada desde el interior de una de las estancias que se abrâ”œÂ¡an al patio del antiguo Cuartel de Caballerâ”œÂ¡a de El Cid, cuando estaba siendo derribado tras haber sido despojado de sus funciones castrenses, tal y como era tradiciâ”œâ”‚n desde que fuera construido allâ”œÃ­ en los remotos tiempos de la Ilustraciâ”œâ”‚n. Al fondo, sobresale levemente la torre-câ”œâ•‘pula de la sucursal de una entidad bancaria local, esquinada entre la plaza del Portillo y General Franco. 47 aâ”œâ–’os despuâ”œÂ®s, de momento, buena parte del gran solar resultante sigue esperando alguna finalidad. Tampoco hay ningâ”œâ•‘n panel informativo arqueolâ”œâ”‚gico que avise de lo que esto fuera, o fuese, por si a alguien, de forma accidental, o harto improbable, llegara a interesarle. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65458000, -0.89325100, '0101000020E610000046D1031F8395ECBFCF4E0647C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23820032459.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23820032459.webp', 'https://www.flickr.com/photos/zaragozaantigua/23820032459/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23936, 'P.â”¬â•‘ de Marâ”œÂ¡a Agustâ”œÂ¡n 1965', '"Vista de Zaragoza desde el estudio", â”œâ”‚leo sobre lienzo, Luis Esteban Ramâ”œâ”‚n, ca. 1965, Interesante visual desde el tramo del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n comprendido entre la calle del General Franco y la de Josâ”œÂ® Anselmo Clavâ”œÂ®. Abajo, instalaciones del cuartel del Cid. Al fondo, alturas de la ciudad, entre el torreâ”œâ”‚n de la plaza del Portillo 2 y la câ”œâ•‘pula de San Ildefonso, tras la plaza de Toros. Fuente visual: zaragozacool.wordpress.com', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65460200, -0.89321800, '0101000020E6100000575A46EA3D95ECBFB6F292FFC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26245745327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26245745327.webp', 'https://www.flickr.com/photos/zaragozaantigua/26245745327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24195, 'Estaciâ”œâ”‚n Campo Sepulcro 1933', 'Estaciâ”œâ”‚n de ferrocarril Campo Sepulcro, de la compaâ”œâ–’â”œÂ¡a MZA. Fuente visual: Foto Conrado Barlâ”œÂ®s, donada por Daniel Barlâ”œÂ®s y digitalizada por Josâ”œÂ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65241500, -0.89512900, '0101000020E610000019709692E5A4ECBFBD35B05582D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23217883536.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23217883536.webp', 'https://www.flickr.com/photos/zaragozaantigua/23217883536/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24201, 'Campo Sepulcro c.1920', 'Imagen de la nueva vâ”œÂ¡a de conexiâ”œâ”‚n entre las instalaciones fabriles de los talleres de Carde y Escoriaza (al fondo), y la estaciâ”œâ”‚n Campo Sepulcro del ferrocarril MZA. Las puertas han sido abiertas, y una locomotora a vapor (posiblemente una 100 con caldera renovada) enfila la curva de acceso ferroviario tirando de material rodante reciâ”œÂ®n terminado. La maniobra, bajo un sol cenital, es seguida atentamente por operarios, tancredos, y pâ”œâ•‘blico en general. Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (CAF), AHPZ.', 1920, 1920, 1920, 'Anos 20', 'DELICIAS', 41.65272800, -0.89660900, '0101000020E61000009293895B05B1ECBF7D9752978CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31690153993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31690153993.webp', 'https://www.flickr.com/photos/zaragozaantigua/31690153993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24463, 'Campo Sepulcro 1924', 'Almacenes de Carbones Pina, de Juan Pâ”œÂ®rez Herrero, en las instalaciones de la Estaciâ”œâ”‚n Ferroviaria de Campo Sepulcro de Zaragoza, con su propio apartadero, en 1924. Fuente: La Esfera, 3 de enero de 1925.', 1924, 1924, 1924, 'Anos 20', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20038867901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20038867901.webp', 'https://www.flickr.com/photos/zaragozaantigua/20038867901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24474, 'Talleres Carde y Escoriaza c.1945', 'Pintura del complejo de la fâ”œÃ­brica de Carde y Escoriaza en su ubicaciâ”œâ”‚n junto a la estaciâ”œâ”‚n de Campo Sepulcro. Permaneciâ”œâ”‚ allâ”œÂ¡ desde los aâ”œâ–’os 20 hasta los 70, fabricando material pesado, como ferrocarriles y tranvâ”œÂ¡as. Fuente: "150 aâ”œâ–’os de ferrocarril en Zaragoza", 2011.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65196900, -0.89757100, '0101000020E610000007D15AD1E6B8ECBFBF805EB873D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20587697371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20587697371.webp', 'https://www.flickr.com/photos/zaragozaantigua/20587697371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24871, 'Estaciâ”œâ”‚n de Campo Sepulcro c.1945', 'Imagen capturada en el punto de situado o lugar autorizado de parada de coches de punto a tracciâ”œâ”‚n animal en la estaciâ”œâ”‚n de Campo Sepulcro o de Madrid, ubicado justo frente al edificio principal de la estaciâ”œâ”‚n al que se accedâ”œÂ¡a por la derecha desde la calle de Anselmo Clavâ”œÂ®. En ese momento perduraban unos 25 coches de punto en activo, al precio de 5 pesetas la hora para tres personas o 6 pesetas la hora para cuatro. El â”œâ•‘ltimo de estos vehâ”œÂ¡culos fue retirado del servicio en 1957.', 1945, 1945, 1945, 'Anos 40', 'DELICIAS', 41.65259300, -0.89482700, '0101000020E6100000467D923B6CA2ECBF9D4CDC2A88D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54982028592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54982028592.webp', 'https://www.flickr.com/photos/zaragozaantigua/54982028592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25062, 'Dos generales y un Alcalde 1927', 'Ayuntamiento de Zaragoza/Foto A. de la Barrera. "General Primo de Rivera". El Alcalde de la ciudad, Miguel Alluâ”œÂ® Salvador (sentado a la izquierda), recoge en la Estaciâ”œâ”‚n Campo Sepulcro, en carruaje oficial, al General y Dictador Miguel Primo de Rivera y Orbaneja, y al general Josâ”œÂ® Sanjurjo Sacanell. Todos sonrâ”œÂ¡en mucho. Datada y comentada por el proyecto GAZA ("Gran Archivo Zaragoza Antigua"), es un compendio de imâ”œÃ­genes de la antigua Zaragoza (Espaâ”œâ–’a), acompaâ”œâ–’adas de textos creados por Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel y la colaboraciâ”œâ”‚n de Antonio Tausiet. adioszaragoza.blogspot.com', 1927, 1927, 1927, 'Anos 20', 'DELICIAS', 41.65216800, -0.89483300, '0101000020E6100000CE35CCD078A2ECBFB6BFB33D7AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938013762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938013762.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938013762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25162, 'Doâ”œâ–’a Blanca de Navarra c.1948', 'Dibujo con la representaciâ”œâ”‚n de las nuevas instalaciones de la fâ”œÃ­brica de camas metâ”œÃ­licas y somieres Alfonso Solans Viamonte, en la calle de Navarra, barriada del Cigarral, en las Delicias. Hasta esta ubicaciâ”œâ”‚n se vino el negocio desde su emplazamiento original, fundado allâ”œÃ­ por 1927 en el arranque del camino de las Fuentes, inmediato a la calle Miguel Servet, cuando Alfonso Solans Viamonte se independizâ”œâ”‚ del negocio camero de su padre Froilâ”œÃ­n Solans Lerâ”œÂ¡n, e iniciâ”œâ”‚ el suyo propio. En este momento, su hijo Alfonso Solans Serrano estaba haciendo lo propio, e iniciaba su carrera empresarial en un local de la calle Santiago Lapuente. En el dibujo, la representaciâ”œâ”‚n de la calle de Navarra, en primer plano, es ciertamente fantasiosa, pues mâ”œÃ­s parece una avenida que el pequeâ”œâ–’o vial con entrada por la avenida de Madrid, y final brusco ante la fâ”œÃ­brica de Material Mâ”œâ”‚vil y Construcciones y el camino de la Mosquetera. Al poco tiempo, la empresa fue redenominada ALSOVISA (Alfonso Solans Viamonte, S.A.), y esta calle mudâ”œâ”‚ su nombre por el de Doâ”œâ–’a Blanca de Navarra para evitar confusiones con la nueva y prometedora avenida de Navarra. A la derecha, la calle del Tenor Gayarre, que la separarâ”œÃ­ de la planta de VIASA. A la izquierda, y tras el cierre de la fâ”œÃ­brica y posterior reurbanizaciâ”œâ”‚n de la zona a mediados de los aâ”œâ–’os 70, se abrirâ”œÃ­ la prolongaciâ”œâ”‚n de la calle Pablo Sarasate. Al fondo, el paso a nivel de las Delicias y vâ”œÂ¡as conducentes al entorno ferroviario de la estaciâ”œâ”‚n de Campo Sepulcro. Fuente visual: www.todocoleccion.net/', 1948, 1948, 1948, 'Anos 40', 'DELICIAS', 41.65345300, -0.89919300, '0101000020E61000001D59F96530C6ECBF8E3C1059A4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32107434036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32107434036.webp', 'https://www.flickr.com/photos/zaragozaantigua/32107434036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26029, 'Vista El Portillo ca. 1975', 'Foto: Colecciâ”œâ”‚n Carlos Carretero. Vista aâ”œÂ®rea centrada en la estaciâ”œâ”‚n de El Portillo. Fuente: www.facebook.com/photo.php?fbid=10211203909242019&set...', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65199500, -0.89483600, '0101000020E61000001212691B7FA2ECBFE813799274D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30450603376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30450603376.webp', 'https://www.flickr.com/photos/zaragozaantigua/30450603376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26036, 'El Portillo 1974', 'Imagen del acceso desde la calle de Josâ”œÂ® Anselmo Clavâ”œÂ® a la reciente estaciâ”œâ”‚n de ferrocarril Zaragoza-El Portillo, donde RENFE concentrâ”œâ”‚ todos los servicios que hasta ese momento prestaban las estaciones de Campo Sepulcro, Delicias, y Arrabal. Tras la moderna construcciâ”œâ”‚n, atisbos del mar de vâ”œÂ¡as de la estaciâ”œâ”‚n, y algunos edificios del entorno de la calle Escoriaza y Fabro, todavâ”œÂ¡a con las naves de la antigua fâ”œÃ­brica de Material Mâ”œâ”‚vil (derecha). A su lado, la descomunal urbanizaciâ”œâ”‚n Parque Roma progresa adecuadamente. La clara maâ”œâ–’ana permite una visual, incluso, del nuevo Hospital Clâ”œÂ¡nico Universitario, allâ”œÃ­ en la calle San Juan Bosco. Fuente visual: www.ebay.es/', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65167300, -0.89466500, '0101000020E6100000E2067C7E18A1ECBFD65757056AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31197955402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31197955402.webp', 'https://www.flickr.com/photos/zaragozaantigua/31197955402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20876, 'El Portillo 1119', 'Segâ”œâ•‘n D. Josef Fâ”œÂ®lix de Amada (1796), estaba Saragoâ”œÂºa reciâ”œÂ®n conquistada por Alfonso I y Gastâ”œâ”‚n de Bâ”œÂ®arn, cuando los moros, que son muy traidores, en gran turba y silencio, y aprovechando la oscuridad de la noche y un notable descuido de los cristianos (los guardas y centinelas estaban en brazos de morfeo), se colaron haciendo una brecha en la muralla de tapial frente a la Aljaferâ”œÂ¡a. Pero la virgen santâ”œÂ¡sima, que velaba por todos los suyos, incluso los descuidados, capitaneâ”œâ”‚ de repente un volante ejâ”œÂ®rcito de espâ”œÂ¡ritus celestiales en forma visible, y les repeliâ”œâ”‚ con el pavor de las soberanas luces que destellaban, y el sangriento estrago que les causâ”œâ”‚. Tamaâ”œâ–’a ruidera despertâ”œâ”‚ finalmente a los guardas, que dieron avisos que sâ”œâ”‚lo sirvieron para testificar el milagro producido: el contorno del Portillo estaba lleno de infinitos moros muertos, ademâ”œÃ­s de una pequeâ”œâ–’a imagen de la reina de los â”œÃ­ngeles que ella misma dejâ”œâ”‚ en la brecha de la muralla por donde se colaron los infieles, como prenda de su protecciâ”œâ”‚n y amparo. Los atâ”œâ”‚nitos lugareâ”œâ–’os celebraron la victoria, y acordaron levantar un magnâ”œÂ¡fico templo para resguardar la material imagen, con el tâ”œÂ¡tulo de Nuestra Seâ”œâ–’ora del Portillo. Acordaron ademâ”œÃ­s no reparar la muralla, que con la virgen bastaba. Los moros padecieron tan espantosa matanza, que ya no volvieron a intentarlo. En la xilografâ”œÂ¡a anâ”œâ”‚nima del siglo XVIII, representaciâ”œâ”‚n simplificada del milagro: a los pies del muro, unos moros se caen al suelo, derribados por la sobrenatural armada, cuya capitana destellea como sol, y eclipsa la brecha abierta. Fuente visual: Wifredo Rincâ”œâ”‚n Garcâ”œÂ¡a, "La Zaragoza de los Sitios", Colecciâ”œâ”‚n Editorial Fundaciâ”œâ”‚n Sitios nâ”¬â•‘ 4, 2008.', 1119, 1119, 1119, 'Siglo XIX', 'DELICIAS', 41.65595200, -0.89345400, '0101000020E61000004E5FCFD72C97ECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18987161143.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18987161143.webp', 'https://www.flickr.com/photos/zaragozaantigua/18987161143/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20909, 'La Aljaferâ”œÂ¡a 1757', 'Miguel Marâ”œÂ¡n. 1757. "Plano en pequeâ”œâ–’o del Castillo de la Aljaferâ”œÂ¡a de Zaragoza con sus contornos para indicar donde se halla colocado, como assi mismo las tierras dependientes de el y el agua que reciven de las dos Azequias de los Rios Jalon y la Huerba"". El dibujo estâ”œÃ­ orientado mirando desde el este, con unas muy interesantes referencias la ubicaciâ”œâ”‚n de la puerta del Portillo, la iglesia y convento de San Agustâ”œÂ¡n, la iglesia del Portillo, la huerta del convento de Santa Inâ”œÂ®s, ademâ”œÃ­s del cauce de las acequias, campos de cultivo, y molino harinero, y la delimitaciâ”œâ”‚n casi catastral de las tierras vinculadas al cuartel de la Aljaferâ”œÂ¡a. Fuente: Servicio Geogrâ”œÃ­fico del Ejâ”œÂ®rcito, Servicio Histâ”œâ”‚rico Militar (Cartoteca, sign. 009/145), Madrid.', 1757, 1757, 1757, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15319052637.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15319052637.webp', 'https://www.flickr.com/photos/zaragozaantigua/15319052637/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20911, 'La Aljaferâ”œÂ¡a 1772', 'L. Jaime. 1846. "Vista geomâ”œÂ®trica de la fachada pr.al del Castillo de la Aljaferâ”œÂ¡a en Zaragoza". La fachada principal se corresponde con el paâ”œâ–’o, o lado, este. La imagen, hoy, estarâ”œÂ¡a dibujada desde la calle de los Diputados. Fuente: "La Aljaferâ”œÂ¡a", Cortes de Aragâ”œâ”‚n, 1998.', 1772, 1772, 1772, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15504951702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15504951702.webp', 'https://www.flickr.com/photos/zaragozaantigua/15504951702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22336, 'Jardâ”œÂ¡n de Invierno 1961', 'Cuadro de jota en el Jardâ”œÂ¡n de Invierno del Cabezo de Buenavista de Zaragoza. Postal, 1961.', 1961, 1961, 1961, 'Anos 60', 'UNIVERSIDAD', 41.63172600, -0.89277800, '0101000020E610000041D3122BA391ECBF3604C765DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19553853706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19553853706.webp', 'https://www.flickr.com/photos/zaragozaantigua/19553853706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20932, 'Aljaferâ”œÂ¡a 1500', 'Dibujo realizado hacia 1875 que ilustra el posible aspecto, desde el noreste, del palacio de la Aljaferâ”œÂ¡a en la â”œÂ®poca de los Reyes Catâ”œâ”‚licos, con su original recinto amurallado, la torre del Homenaje culminada en mirador y la iglesia de la parroquia de San Martâ”œÂ¡n. Fuente visual: www.cortesaragon.es/', 1500, 1500, 1500, 'Siglo XIX', 'DELICIAS', 41.65656600, -0.89697300, '0101000020E6100000E8A38CB800B4ECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25174985037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25174985037.webp', 'https://www.flickr.com/photos/zaragozaantigua/25174985037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20958, 'Puerta del Portillo c.1800', '"Puerta del Portillo", Antonio Callaved, 2012. De origen medieval, fue destruida en los sitios y vuelta a construir, hasta ser derribada en 1868. A la derecha, iglesia del Portillo. Se ubicaba en la actual calle de Conde de Aranda. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1800, 1800, 1800, 'Siglo XIX', 'DELICIAS', 41.65597400, -0.89272400, '0101000020E610000075560BEC3191ECBF5E83BEF4F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15280181625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15280181625.webp', 'https://www.flickr.com/photos/zaragozaantigua/15280181625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21000, 'N.â”¬Â¬ S.â”¬Â¬ del Portillo 1827', 'Fotografâ”œÂ¡a realizada sobre 1880 por Anselmo Marâ”œÂ¡a Coyne del dibujo que representaba el proyecto de rehabilitaciâ”œâ”‚n de la tardobarroca iglesia parroquial de Nuestra Seâ”œâ–’ora del Portillo, realizado en 1827 por el arquitecto Josâ”œÂ® de Yarza y Miâ”œâ–’ana al objeto de reconstruirla tras los daâ”œâ–’os sufridos durante los asedios franceses de 1808-1809. En este caso, se trata del dibujo de la fachada principal de la iglesia, con el gran pâ”œâ”‚rtico en arco de medio punto por el que se ingresa a su interior desde la plaza del Portillo. Esta obra se mantuvo inconclusa hasta la dâ”œÂ®cada de los aâ”œâ–’os ochenta del pasado siglo XX, cuando el arquitecto Josâ”œÂ® Manuel Pâ”œÂ®rez Latorre reinterpretâ”œâ”‚ el proyecto dejâ”œÃ­ndolo tal y como ahora es visible. Josâ”œÂ® de Yarza y Miâ”œâ–’ana participâ”œâ”‚ tambiâ”œÂ®n en los proyectos de reconstrucciâ”œâ”‚n (algunos realizados, otros no) de un buen nâ”œâ•‘mero de iglesias, conventos y monasterios afectados por los referidos asedios, como la iglesia y convento de Santa Mâ”œâ”‚nica, el Real Monasterio de Santa Engracia, el convento de los Capuchinos, el convento de los Trinitarios Descalzos, y la iglesia parroquial de N.â”¬Â¬ S.â”¬Â¬ de Altabâ”œÃ­s. Fuente visual: Archivo Coyne, en AHPZ', 1827, 1827, 1827, 'Siglo XIX', 'DELICIAS', 41.65586500, -0.89282000, '0101000020E6100000FCDEA63FFB91ECBFA7CB6262F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45008437781.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45008437781.webp', 'https://www.flickr.com/photos/zaragozaantigua/45008437781/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21048, 'Cuartel Aljaferâ”œÂ¡a 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1874-1877. "Vista del Cuartel de la Aljaferâ”œÂ¡a con soldados." El Regimiento de Galicia, alojado en este "Cuartel", posa en disposiciâ”œâ”‚n de revista.', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65614400, -0.89646900, '0101000020E610000022179CC1DFAFECBFBABBCE86FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14679640338.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14679640338.webp', 'https://www.flickr.com/photos/zaragozaantigua/14679640338/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21064, 'La Aljaferâ”œÂ¡a 1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1874-1877. "Vista del Cuartel de la Aljaferâ”œÂ¡a." El Regimiento de Galicia, alojado en este "Cuartel", aâ”œâ•‘n no ha salido para posar en posiciâ”œâ”‚n de revista, delante del antiguo Palacio de la Alegrâ”œÂ¡a. El fotâ”œâ”‚grafo aprovecha para realizar una captura de prueba.', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15503036261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15503036261.webp', 'https://www.flickr.com/photos/zaragozaantigua/15503036261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21104, 'Plaza del Portillo 1889', '"Saragosse. Vue gâ”œÂ®nerale". J. Lâ”œÂ®vy et Cie. Una dâ”œÂ®cada despuâ”œÂ®s de que J. Laurent et Cie. nos impactara con su fenomenal vista panorâ”œÃ­mica de la ciudad desde las alturas de la iglesia del Portillo, J. Levy et Cie. se suben tambiâ”œÂ®n al mismo punto para realizar una â”œâ•‘nica captura, no menos interesante. A los pies sigue la circular plaza del Portillo, a la que desembocan las paralelas calles del Portillo y Agustina de Aragâ”œâ”‚n. A la izquierda, inmediatos, algunos cambios: el muro de la huertas y convento de Santa Inâ”œÂ®s, ya estâ”œÃ­n retranqueados como signo de que el ensanchamiento de la estrecha calle del Portillo va en serio. Su estrechez no habâ”œÂ¡a sido problema durante siglos: por ejemplo, cuando un monarca entraba por la puerta del Portillo, giraba por Santa Inâ”œÂ®s, giraba de nuevo hacia San Pablo, y llegaba directo a la plaza del Mercado. Ahora se argumentaba que era necesario dar amplitud a la calle como acceso directo al Coso, lo que requerâ”œÂ¡a ampliarla, sanearla, y de paso, dar algâ”œâ•‘n pelotazo urbanâ”œÂ¡stico. Dicho y hecho, aunque costarâ”œÂ¡a un tiempo. Este ensanchamiento se llevarâ”œÂ¡a una parte de la antigua "Casa de la Galera", el complejo que hace esquina con Santa Inâ”œÂ®s, que luego desempeâ”œâ–’â”œâ”‚ funciones de câ”œÃ­rcel, y que desde 1883 habâ”œÂ¡a sido reconvertido en escuela de niâ”œâ–’os... Los mismos recortes afectaron a muchos edificios de esta calle, hasta el Coso. Esta es la gâ”œÂ®nesis de la posteriormente denominada calle Conde de Aranda. Al fondo, sobre los tejados, la lâ”œÂ¡nea de torres de la ciudad, cambiante segâ”œâ•‘n el ritmo de los derribos. De izquierda a derecha: el Pilar, San Pablo, Santa Isabel, San Salvador y su cimborrio, la Torre Nueva (pre-muerta), San Felipe y Santiago el Menor, las Escuelas Pâ”œÂ¡as, San Juan y San Pedro, La Magdalena, el palacio de Morata, San Gil, San Carlos, San Miguel, y San Ildefonso. Cerca de â”œÂ®sta, apenas cuatro aâ”œâ–’os antes aâ”œâ•‘n se levantaba la torre del antiguo convento de los Mâ”œÂ¡nimos de la Victoria. Fuente visual: Zaragoza en la mirada ajena. Cortes de Aragâ”œâ”‚n, 2012', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19115472282.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19115472282.webp', 'https://www.flickr.com/photos/zaragozaantigua/19115472282/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21112, 'Aljaferâ”œÂ¡a 1889', '"Saragosse. Caserne de l''Aljaferia". Antiguo palacio, cuando era dependencia cuartelaria del Ministerio de la Guerra. Imagen capturada desde la carretera a Madrid. Sobresalen, al fondo, la torre del homenaje, y los restos desmochados de la torrecilla de la iglesia de San Martâ”œÂ¡n. Fuente: J. Lâ”œÂ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65617600, -0.89651200, '0101000020E6100000F4160FEF39B0ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22750553871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22750553871.webp', 'https://www.flickr.com/photos/zaragozaantigua/22750553871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21126, 'La Aljaferâ”œÂ¡a 1889', '"Puerta trasera del oratorio islâ”œÃ­mico de la Aljaferâ”œÂ¡a". Esta puerta se encuentra hoy cegada, frente a la entrada principal del palacio, en el patio de San Martâ”œÂ¡n. Fuente: J. Lâ”œÂ®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Aragâ”œâ”‚n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'DELICIAS', 41.65671000, -0.89669400, '0101000020E61000001F9F909DB7B1ECBF637AC2120FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40289731665.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40289731665.webp', 'https://www.flickr.com/photos/zaragozaantigua/40289731665/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21221, 'Aljaferâ”œÂ¡a 1900', 'En domingo, y desde la Ribera Baja, una excursiâ”œâ”‚n a Zaragoza a merendar y tirar unas fotos, que el tiempo acompaâ”œâ–’a. La merienda, ya ha tendido lugar en los tranquilos y arbolados alrededores del cuartel de la Aljaferâ”œÂ¡a, por la parte de detrâ”œÃ­s, no lejos del amistoso polvorâ”œÂ¡n donde unos aâ”œâ–’os despuâ”œÂ®s se habilitarâ”œÃ­ el "homâ”œâ”‚dromo", o minicampo de maniobras para los efectivos cuartelarios. El posado, perfectamente ordenado de menor a mayor importancia (chavalerâ”œÂ¡a, mujeres, hombre, cura) junto a la vâ”œÂ¡a del ferrocarril de Madrid a Barcelona, no lejos del Camino de Herederos y del Convento de los Carmelitas Descalzos de San Josâ”œÂ®, apenas a unas decenas de metros. Al fondo, panorama urbano del momento. A la izquierda, la rotunda silueta del castillo-cuartel. Por encima sobresale la torre de Santiago del Pilar, junto a la mole de la Torre del Trovador. A la derecha, câ”œâ•‘pula y torrecillas de la Real Casa de la Misericordia. El humo, de la activa Fundiciâ”œâ”‚n Averly. Fuente visual: quintodeebro.com/ Familia Florencio Jardiel Dobato', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65670500, -0.89965500, '0101000020E610000027DA5548F9C9ECBF520FD1E80ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15915606913.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15915606913.webp', 'https://www.flickr.com/photos/zaragozaantigua/15915606913/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21263, 'El Portillo 1907', 'Postal. "Colecciâ”œâ”‚n Patria y Fe nâ”œâ•‘m. 7, Zaragoza 1908 - Centenario de los Sitios", 1907. "Esta puerta es la que Agustina de Aragâ”œâ”‚n defendiâ”œâ”‚ heroicamente, en el ataque del 2 de julio, salvando a la ciudad en uno de los momentos de mayor peligro." Vista del emplazamiento de la antigua puerta del Portillo, en la esquina de la iglesia del Portillo con la calle del Conde de Aranda y el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n actuales. Fuente: www.pasapues.es/', 1907, 1907, 1907, 'Anos 1900', 'DELICIAS', 41.65622400, -0.89352900, '0101000020E6100000F8E12021CA97ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20767895975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20767895975.webp', 'https://www.flickr.com/photos/zaragozaantigua/20767895975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21664, 'Plaza del Portillo 1930', '"Iglesia de Nuestra Seâ”œâ–’ora del Portillo".', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65575900, -0.89275700, '0101000020E610000064CDC8207791ECBF628731E9EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14681281839.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14681281839.webp', 'https://www.flickr.com/photos/zaragozaantigua/14681281839/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21692, 'Plaza del Portillo 1930', '"Plaza del Portillo y monumento a Agustina de Aragâ”œâ”‚n". Imagen tomada con la iglesia del Portillo como telâ”œâ”‚n de fondo del monumento. Mâ”œÃ­s al fondo, a la derecha, la calle del Conde Aranda, con vista de los muros tras los que estaban los enormes huertos del convento de Santa Inâ”œÂ®s.', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060071759.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060071759.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060071759/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21810, 'Plaza del Portillo 1930', 'Imagen capturada, de buena maâ”œâ–’ana, en los jardines de la plaza del Portillo. Al fondo, la iglesia decimonâ”œâ”‚nica y homâ”œâ”‚nima, y la despejada vista de ese tramo de la antigua calle del Portillo, entonces recayente a los muros de la enorme huerta conventual de Santa Inâ”œÂ®s. Como valor aâ”œâ–’adido, y en primerâ”œÂ¡simo plano, la sombra del fotâ”œâ”‚grafo portuguâ”œÂ®s Antâ”œâ”‚nio Passaporte en el ejercicio de su profesiâ”œâ”‚n.', 1930, 1930, 1930, 'Anos 30', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29783242092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29783242092.webp', 'https://www.flickr.com/photos/zaragozaantigua/29783242092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21883, 'La Aljaferâ”œÂ¡a 1931', 'Imagen capturada junto al soterrano cauce de la acequia de la Romareda Baja, o del Boquerazo, en el tramo paralelo a la carretera de Madrid a Francia. Tras los â”œÃ­rboles y al fondo, explanada de acceso al cuartel de la Aljaferâ”œÂ¡a, cuando era sede de los regimientos de infanterâ”œÂ¡a "Infante" y "Gerona" del Ejâ”œÂ®rcito. Este antiguo palacio presentaba la traza conferida en la reforma que entre 1860-80 lo consolidâ”œâ”‚ como dependencia cuartelera, como era tradiciâ”œâ”‚n desde los albores del siglo XVIII, cuando la Guerra de Sucesiâ”œâ”‚n. Sobre el paâ”œâ–’o de la fachada principal destacan las marquesinas de los dos accesos. Sobre el tejado emerge la cuadrangular Torre del Trovador, cubierta, y la torrecilla de la iglesia de San Martâ”œÂ¡n.', 1931, 1931, 1931, 'Anos 30', 'DELICIAS', 41.65598400, -0.89540700, '0101000020E6100000CB80B3942CA7ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49116449481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49116449481.webp', 'https://www.flickr.com/photos/zaragozaantigua/49116449481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21991, 'La Aljaferâ”œÂ¡a 1944', 'Imagen capturada durante una inspecciâ”œâ”‚n, o revista, del regimiento de artillerâ”œÂ¡a antiaâ”œÂ®rea nâ”¬â•‘ 73, llevada a cabo en la explanada de acceso al cuartel de la Aljaferâ”œÂ¡a, cuya luminosa fachada principal aparece al fondo. El caâ”œâ–’â”œâ”‚n objeto de admiraciâ”œâ”‚n era uno de los impresionantes 8,8-cm-Flak, posiblemente el modelo 36, que los aliados alemanes habâ”œÂ¡an introducido en la penâ”œÂ¡nsula durante la guerra de 1936-39 como ayuda del Reich de los 1000 aâ”œâ–’os a la Espaâ”œâ–’a nacionalista. El 4 de junio de 1931, el Palacio de la Aljaferâ”œÂ¡a habâ”œÂ¡a sido declarado Monumento Nacional de Interâ”œÂ®s Histâ”œâ”‚rico-Artâ”œÂ¡stico. Fuente visual: www.todocoleccion.net/', 1944, 1944, 1944, 'Anos 40', 'DELICIAS', 41.65654200, -0.89635300, '0101000020E6100000D47C957CECAEECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30897108105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30897108105.webp', 'https://www.flickr.com/photos/zaragozaantigua/30897108105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22127, 'P.â”¬â•‘ de Marâ”œÂ¡a Agustâ”œÂ¡n 1951', 'Imagen del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n en su tramo en destacado descenso desde el Portillo, y hasta la Puerta Sancho, abajo. Hacia la izquierda, se abren las calles Teniente Coronel Pueyo, primero, y Aljaferâ”œÂ¡a, despuâ”œÂ®s. Al fondo, donde la pronunciada curva a la derecha, la calle de Santa Lucâ”œÂ¡a lleva a un paso a nivel ferroviario que permite al acceso a la Almozara y la Quâ”œÂ¡mica. En la despejada calzada, vâ”œÂ¡as del tranvâ”œÂ¡a de la lâ”œÂ¡nea 7 "Ayuntamiento-Puerta Sancho". Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'DELICIAS', 41.65651900, -0.89368000, '0101000020E610000062DBA2CC0699ECBFF01989D008D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23159027235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23159027235.webp', 'https://www.flickr.com/photos/zaragozaantigua/23159027235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22352, 'La Aljaferâ”œÂ¡a 1966', 'Cuartel del Prâ”œÂ¡ncipe en el palacio de la Aljaferâ”œÂ¡a. Fuente: "Espaâ”œâ–’a, quâ”œÂ® hermosa eres", 1966.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20562363812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20562363812.webp', 'https://www.flickr.com/photos/zaragozaantigua/20562363812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22367, 'Paso a nivel de Delicias 1967', 'Imagen del paso a nivel de Delicias con el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n al fondo, el 24 de junio de 1967. Confluencia de diversos medios de transporte en la actual plaza de la Ciudadanâ”œÂ¡a. Fuente: Asociaciâ”œâ”‚n Paso a Nivel.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21395637735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21395637735.webp', 'https://www.flickr.com/photos/zaragozaantigua/21395637735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22383, 'Calle Boggiero 1962', 'Fielato del Portillo, en la esquina de la calle de Basilio Boggiero (derecha) con el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. En la puerta, parte del equipo de la Policâ”œÂ¡a Sanitaria de Abastos, que controlaba el estado de los productos alimentarios y procedâ”œÂ¡a al cobro de sus tasas. Fuente visual: Boletâ”œÂ¡n Municipal de Zaragoza.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65694400, -0.89343400, '0101000020E6100000874D64E60297ECBFD7A6B1BD16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22390669160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22390669160.webp', 'https://www.flickr.com/photos/zaragozaantigua/22390669160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22438, 'Paso a nivel Delicias c.1968', 'Continuaciâ”œâ”‚n de la imagen anterior, en el entorno del antiguo paso a nivel ferroviario de Delicias. En primer plano, proveniente de la estaciâ”œâ”‚n de Campo Sepulcro, traquetea una poderosa locomotora a vapor del tipo 1-5-1, "Santa Fe", pasando junto a la Torre de agujas ferroviarias ubicada en la esquina noreste del paso a nivel. Detrâ”œÃ­s, la estructura del metâ”œÃ­lico puente de seâ”œâ–’ales ferroviarias, algunos edificios de la avenida de Madrid, y al fondo, el mar de vâ”œÂ¡as de Campo Sepulcro y los grandes bloques de viviendas de la avenida de Anselmo Clavâ”œÂ®. Fuente visual: www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65548900, -0.89832400, '0101000020E6100000EBC726F911BFECBFA2F14410E7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30767140540.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30767140540.webp', 'https://www.flickr.com/photos/zaragozaantigua/30767140540/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22483, 'Av. de Madrid 1968', 'Imagen capturada en el principio de la avenida de Madrid, con el fondo edilicio de la pequeâ”œâ–’a manzana entre la avenida, la calle del Comandante Rodrâ”œÂ¡guez de Câ”œâ”‚rdoba, y la calle del Castillo. En el centro de la imagen, el pequeâ”œâ–’o y antiguo inmueble del nâ”¬â•‘ 2 de la calle del Castillo, luego derribado y sustituido por un edificio mâ”œÃ­s moderno y vertical. De fondo, los grandes bloques del â”œâ•‘ltimo tramo de los nâ”œâ•‘meros pares de la calle del General Franco, chaflanero el â”œâ•‘ltimo con el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n. A la derecha, vista parcial de las traseras de la iglesia del Portillo. Transita la composiciâ”œâ”‚n tranviaria M+R nâ”¬â•‘ 108 en servicio en la lâ”œÂ¡nea 5 "Venecia-Delicias", encaminada hacia la plaza de Espaâ”œâ–’a para ascender luego hasta ese barrio del sur, pasado el Canal Imperial de Aragâ”œâ”‚n. Fuente visual: foto Charles F. Firminger en "30937 Transport Photograph Database".', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65603400, -0.89423600, '0101000020E6100000C6FCDCD0949DECBF33880FECF8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40075841073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40075841073.webp', 'https://www.flickr.com/photos/zaragozaantigua/40075841073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22519, 'Aljaferâ”œÂ¡a 1966', 'Vista aâ”œÂ®rea centrada en el antiguo palacio de la Aljaferâ”œÂ¡a, todavâ”œÂ¡a bajo jurisdicciâ”œâ”‚n militar con funciones cuarteleras. En su aspecto destacan las primeras obras de restauraciâ”œâ”‚n acometidas bajo la direcciâ”œâ”‚n del arquitecto Francisco â”œÃ¬â”œâ–’iguez Almech. Rodean al cuartel otras instalaciones militares adosadas y extentas, como su antiguo polvorâ”œÂ¡n y el "homâ”œâ”‚dromo". En primer tâ”œÂ®rmino, naves de la fâ”œÃ­brica de muebles de Loscertales.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65663100, -0.89592200, '0101000020E61000008B8A389D64ABECBF17450F7C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53286721558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53286721558.webp', 'https://www.flickr.com/photos/zaragozaantigua/53286721558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22813, 'P.â”¬â•‘ de Marâ”œÂ¡a Agustâ”œÂ¡n 1974', 'Inâ”œÂ®dita imagen capturada en la estratâ”œÂ®gica esquina entre el arranque de la avenida de Madrid y el tramo del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n que al fondo ofrece su aspecto en ese momento, entre el cuartel del Cid, a la derecha, y las traseras de la iglesia de N.â”¬Â¬ S.â”¬Â¬ del Portillo. Entre ambos ruinosos entornos se abre la moderna calle que conecta con la plaza del Portillo y que desde 1968 homenajeaba a Jesâ”œâ•‘s Muro Sevilla como jefe provincial de Falange Espaâ”œâ–’ola el 18 de julio de 1936. En primer tâ”œÂ®rmino, frecuentado observatorio o mirador donde algunos de los parroquianos del inmediato Cafâ”œÂ® Madrid (justo a la derecha y fuera de plano), mayormente vinculados con el sector del transporte carretero en camiâ”œâ”‚n (châ”œâ”‚feres, ayudantes, descargadores), "hacen tiempo" entre carga y carga. Algunos de ellos probablemente tendrâ”œÃ­n estacionado el camiâ”œâ”‚n en la cercana explanada junto al castillo de la Aljaferâ”œÂ¡a. El inmediato barrio del Castillo, al otro lado de la avenida de Madrid, concentraba un buen nâ”œâ•‘mero de despachos de oficina de empresas de transporte.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65585500, -0.89395800, '0101000020E610000014ECBFCE4D9BECBF84F57F0EF3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51561016174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51561016174.webp', 'https://www.flickr.com/photos/zaragozaantigua/51561016174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22864, 'Portillo 1987', 'Desde la torre de la iglesia de Nâ”¬Â¬ Sâ”¬Â¬ del Portillo mâ”œÃ­s cercana a la calle Conde Aranda, un vistazo en altura al sureste urbano de la mano de Luis Mâ”œÂ¡nguez, que nos da una buena visual de la inmediata plaza del Portillo, con el estado de las antiguas parcelas del arranque de la calle Pignatelli (izquierda). En lâ”œÂ¡nea recta, varios edificios referenciales de lo que fueran las Eras del Campo del Toro: el Coso de la Misericordia, antes de su cubrimiento, y la antigua Real Casa de la Misericordia, sede de la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n desde 1983, en obras de restauraciâ”œâ”‚n de su neobizantina iglesia. Al fondo, el edificio Ebrosa, absolutista tope visual. En la calle Madre Rafols, emergen las torres del convento de las Hermanas de la Caridad de Santa Ana. Enfrente, los esquineros y deshabitados edificios para mandos del antiguo cuartel de Sangenis. Por el fondo, y como contrastado telâ”œâ”‚n de fondo, los grandes bloques de la avenida de Câ”œÂ®sar Augusto.', 1987, 1987, 1987, 'Anos 80', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15662110277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15662110277.webp', 'https://www.flickr.com/photos/zaragozaantigua/15662110277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22904, 'Muebles Loscertales 1989', 'Imagen del acceso a la fâ”œÃ­brica de muebles de alta gama Simâ”œâ”‚n Loscertales Bona, en la calle Aljaferâ”œÂ¡a, donde terminaba la calle Comandante Rodrâ”œÂ¡guez de Câ”œâ”‚rdoba (desde 2009, Sebastiâ”œÃ­n Banzo Urrea), tal y como estaba el 20 de febrero de 1989. Habâ”œÂ¡a cerrado sus puertas en 1985. Fuente: "Memoria de las calles de Zaragoza", Juliâ”œÃ­n Ruiz Marâ”œÂ¡n, Librerâ”œÂ¡a General, 2003.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65724800, -0.89540900, '0101000020E6100000F96871C630A7ECBF43AED4B320D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21742335371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21742335371.webp', 'https://www.flickr.com/photos/zaragozaantigua/21742335371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22968, 'Restauraciâ”œâ”‚n de La Aljaferâ”œÂ¡a 1994', 'Jesâ”œâ•‘s Lacueva. La Aljaferâ”œÂ¡a (1994): trabajos de construcciâ”œâ”‚n del sâ”œâ”‚tano-almacâ”œÂ®n del Patio de las Cortes. El desmoche de la techumbre de enfrente (lado Norte) se practicâ”œâ”‚ para colocar la estructura de madera de la sala de comisiones C (despuâ”œÂ®s, sala "Manuel Gimâ”œÂ®nez Abad"); el de la derecha, para ubicar los grupos parlamentarios y la sala "Goya". Fuente: Manuel Ballarâ”œÂ¡n.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65637500, -0.89690300, '0101000020E6100000B0E595EB6DB3ECBFBC74931804D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945038411.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945038411.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945038411/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22970, 'Paso a nivel Delicias aâ”œâ–’os 90', 'A finales de los aâ”œâ–’os 80 del siglo XX, se decidiâ”œâ”‚ que el estado de insalubridad y estrechamiento para los peatones en el paso a nivel ferroviario, carretero y peatonal de Delicias era insostenible. Asâ”œÂ¡ que se construyâ”œâ”‚ lo que se dio en llamar "Mecano", con su bola blanca gigante posmoderna. En 2001 se desmontâ”œâ”‚ y se soterraron las vâ”œÂ¡as.', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65527500, -0.89784300, '0101000020E610000030293E3E21BBECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15009511522.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15009511522.webp', 'https://www.flickr.com/photos/zaragozaantigua/15009511522/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23002, 'Avenida de Madrid aâ”œâ–’os 90', 'Vista del paso elevado peatonal sobre la avenida de Madrid. Al fondo, barrio de Las Delicias. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321240142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321240142.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321240142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23004, 'Palacio de la Aljaferâ”œÂ¡a aâ”œâ–’os 90', 'Vista del Palacio de la Aljaferâ”œÂ¡a, una vez concluida su restauraciâ”œâ”‚n. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65598100, -0.89714700, '0101000020E61000005D8B16A06DB5ECBF10E6762FF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422108855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422108855.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422108855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23035, 'Paso Delicias 1990', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 1 de la calle de Juan XXIII con una panorâ”œÃ­mica vista del entorno del reciâ”œÂ®n inaugurado paso elevado de Delicias, que en el centro de la escena fue construido por el Ayuntamiento para permitir a los peatones atravesar el enlace a la autopista de Logroâ”œâ–’o, las vâ”œÂ¡as del ferrocarril conducentes a la estaciâ”œâ”‚n del Portillo, y dar asâ”œÂ¡ continuidad a la avenida de Madrid de la misma forma que el paso a desnivel permitâ”œÂ¡a al trâ”œÃ­fico rodado. Esta infraestructura costâ”œâ”‚ 450 millones de pesetas y estuvo en construcciâ”œâ”‚n desde mayo de 1988 a abril de 1990. Fue inaugurado oficialmente el 27 de abril de este â”œâ•‘ltimo aâ”œâ–’o. En primer tâ”œÂ®rmino y a la izquierda, el colegio pâ”œâ•‘blico Juan XXIII, y tras la zona ocupada por las vâ”œÂ¡as del ferrocarril y la autopista, vista del lienzo occidental del palacio de la Aljaferâ”œÂ¡a, que sigue en obras, con la traza preservada del decimonâ”œâ”‚nico cuartel. A la derecha, la ancha calle de Escoriaza y Fabro y la de Sâ”œÃ­daba, paralela a las vâ”œÂ¡as, y entre ambas, solar en forma de "quesito" que en 1994 serâ”œÂ¡a urbanizado.', 1990, 1990, 1990, 'Anos 90', 'DELICIAS', 41.65525400, -0.89804600, '0101000020E610000039B709F7CABCECBF5E49F25CDFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50308514688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50308514688.webp', 'https://www.flickr.com/photos/zaragozaantigua/50308514688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23055, 'Paso a nivel Delicias 1994', 'Imagen, que con el tiempo se convertirâ”œÂ¡a en recurrente, centrada en las escaleras mecâ”œÃ­nicas del reciente paso elevado de Delicias estropeadas, en este caso por los daâ”œâ–’os producidos por modernos luditas urbanos que encuentran sentido a su vida destrozando el mobiliario pâ”œâ•‘blico. Como informa el cartel, para estas ocasiones debâ”œÂ¡a utilizarse la rampa cuyo uso significaba una notable inversiâ”œâ”‚n de tiempo. Al fondo y tras la trinchera ferroviaria, inmueble del principio de la calle de Juan XXIII.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65540700, -0.89769200, '0101000020E6100000C72FBC92E4B9ECBFE4486760E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50446814942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50446814942.webp', 'https://www.flickr.com/photos/zaragozaantigua/50446814942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23068, 'Paso Elevado Delicias 2000', '2000. "Paso a Nivel con estructura metâ”œÃ­lica". Construido a finales de los 80 supuestamente para beneficio de las personas a pie, fue desmontado en 2001, con apenas una dâ”œÂ®cada de vida â”œâ•‘til, a pesar de lo anunciado por el Boletâ”œÂ¡n (para)Oficial del Ayuntamiento (Revista "Nuestra Zaragoza", agosto-setiembre 1989): "Su diseâ”œâ–’o y estructura han sido concebidos para convertirse en un punto de referencia de la arquitectura urbana. Para facilitar la vida de los paseantes el Alcalde ha dado instrucciones de que se modifique ligeramente el proyecto de forma que los peatones puedan acceder al paso mediante escaleras mecâ”œÃ­nicas o rampas mâ”œâ”‚viles, puesto que los cinco metros de desnivel pueden ser muy fatigosos para personas mayores o que llevan paquetes". Personas mayores, portaquetes, y paseantes en general quedamos muy agradecidos al (ex) Alcalde Triviâ”œâ–’o por sus desvelos, se encuentre donde se encuentre.', 2000, 2000, 2000, 'Siglo XXI', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14785329388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14785329388.webp', 'https://www.flickr.com/photos/zaragozaantigua/14785329388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23133, 'Jacques Chirac 2004', 'Foto: Josâ”œÂ® Miguel Marco. Jacques Chirac, presidente de la Repâ”œâ•‘blica Francesa entre 1995 y 2007, pasea por la Aljaferâ”œÂ¡a flanqueado por el presidente del Reino de Espaâ”œâ–’a, Josâ”œÂ® Luis Rodrâ”œÂ¡guez Zapatero, y el de la Comunidad Autâ”œâ”‚noma de Aragâ”œâ”‚n, Marcelino Iglesias. Es el 7 de diciembre de 2004, y se celebra la XVII Cumbre hispano-francesa. Fuente: Heraldo de Aragâ”œâ”‚n.', 2004, 2004, 2004, 'Siglo XXI', 'DELICIAS', 41.65661900, -0.89682700, '0101000020E6100000F06E6589CEB2ECBF537765170CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31708731961.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31708731961.webp', 'https://www.flickr.com/photos/zaragozaantigua/31708731961/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23198, 'Paseo Marâ”œÂ¡a Agustâ”œÂ¡n 2015', 'Obras de renovaciâ”œâ”‚n de tuberâ”œÂ¡as en el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, en su confluencia con la avenida de Madrid (al fondo), en octubre de 2015. Destaca en el centro el estado ruinoso del edificio del antiguo Cafâ”œÂ® Madrid (1889-1997), que alberga el restaurante Casa Emilio (1939). Su fachada fue remozada en 2017. Fuente: www.zaragoza.es', 2015, 2015, 2015, 'Siglo XXI', 'DELICIAS', 41.65607700, -0.89380800, '0101000020E6100000C1E61C3C139AECBF3354C554FAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25699741837.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25699741837.webp', 'https://www.flickr.com/photos/zaragozaantigua/25699741837/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23213, 'La Aljaferâ”œÂ¡a 2014', 'Foto: Maroiane B. En agosto de 2014 se difundieron varias fotografâ”œÂ¡as en las que se reivindicaba al grupo armado integrista ISIS en distintos lugares de Espaâ”œâ–’a, tras autoproclamar un califato con capital en Mosul, Irak, una vez invadida. En 2017, el gobierno iraquâ”œÂ¡ recuperâ”œâ”‚ esa ciudad. Aquâ”œÂ¡ podemos ver la bandera de tal organizaciâ”œâ”‚n, ante el palacio de la Aljaferâ”œÂ¡a de Zaragoza. La instantâ”œÃ­nea estâ”œÃ­ tomada en su esquina noreste, junto al foso. Al fondo, bloque de viviendas de la avenida de Madrid esquinero con la plaza de la Ciudadanâ”œÂ¡a. Fuente: Agencia EFE.', 2014, 2014, 2014, 'Siglo XXI', 'DELICIAS', 41.65718000, -0.89630800, '0101000020E6100000D594641D8EAEECBFEACA67791ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36039001464.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36039001464.webp', 'https://www.flickr.com/photos/zaragozaantigua/36039001464/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23245, 'Saraqusta 1115', '"Sarakosta", dibujo de Josâ”œÂ® Luis Cano que representa el palacio de la Aljaferâ”œÂ¡a. En el centro, el filâ”œâ”‚sofo Avempace (1080-1139), cuando fue nombrado visir del gobernador almorâ”œÃ­vide Ibn Tifilwit. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 1115, 1115, 1115, 'Siglo XIX', 'DELICIAS', 41.65660300, -0.89699900, '0101000020E6100000376E313F37B4ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31811731450.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31811731450.webp', 'https://www.flickr.com/photos/zaragozaantigua/31811731450/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23247, 'Saraqusta 1067', 'Fantâ”œÃ­stica imagen creada por ordenador para la serie "El Cid" que representa supuestamente la Saraqusta de la Taifa gobernada por Al-Muqtâ”œÃ­dir Billah cuando las tropas del rey Sancho II de Castilla comandadas por ''Ruy'' Dâ”œÂ¡az de Vivar se aproximan a ella para cobrar "las parias". La imagen presenta una recreaciâ”œâ”‚n muy lograda de una ciudad medieval aparentemente musulmana, con sus murallas, alminares variados y câ”œâ•‘pulas de colores, si bien parece poco probable para la Saraqusta de la â”œÂ®poca. Las tropas en su aproximaciâ”œâ”‚n por el oeste deberâ”œÂ¡an encontrarse primero con la Al-Ja''Fariyya (La Aljaferâ”œÂ¡a), construcciâ”œâ”‚n exenta y fuera del perâ”œÂ¡metro amurallado, que aquâ”œÂ¡ no aparece cuando deberâ”œÂ¡a hacerlo justo a la izquierda de la puerta de la muralla. Ademâ”œÃ­s el ingreso a la ciudad no era tan desolador por tratarse de una zona regada con el agua de varias acequias (Almozara y Romareda). Y las montaâ”œâ–’as del fondo no se corresponden con el relieve de la Sierra de Alcubierre.', 1067, 1067, 1067, 'Siglo XIX', 'DELICIAS', 41.65624000, -0.89439800, '0101000020E61000002A73F38DE89EECBFDC291DACFFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51323388974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51323388974.webp', 'https://www.flickr.com/photos/zaragozaantigua/51323388974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23248, 'La Aljaferâ”œÂ¡a 1118', 'Portada del câ”œâ”‚mic "Misterio en el valle del Viento", primera entrega de "Las aventuras de Fâ”œÃ­tima". Con dibujos de Alfonso Pinedo y guion de Carlos Cabrero y Miguel â”œÃ¼ngel Fecâ”œÂ®, la historieta se sitâ”œâ•‘a en los momentos en que Alfonso I el Batallador se dispone a tomar Saraqusta. En la ilustraciâ”œâ”‚n, los protagonistas aparecen con el palacio de la Aljaferâ”œÂ¡a detrâ”œÃ­s, minarete incluido. Esta obra rinde homenaje con su estilo al de Hergâ”œÂ®, creador de Tintâ”œÂ¡n.', 1118, 1118, 1118, 'Siglo XIX', 'DELICIAS', 41.65663100, -0.89592200, '0101000020E61000008B8A389D64ABECBF17450F7C0CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52100345769.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52100345769.webp', 'https://www.flickr.com/photos/zaragozaantigua/52100345769/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23252, 'Aljaferâ”œÂ¡a 1737', 'Cristâ”œâ”‚bal Cubero. 1737. "Plano del fuerte de la Aljaferia de Zaragoza, con la Plaza de Armas, delante de la principal puerta". El dibujo estâ”œÃ­ orientado mirando desde el este. Fuente: www.mcu.es/', 1737, 1737, 1737, 'Siglo XIX', 'DELICIAS', 41.65649000, -0.89644500, '0101000020E61000000135B56CADAFECBF551344DD07D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16616536792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16616536792.webp', 'https://www.flickr.com/photos/zaragozaantigua/16616536792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22371, 'Vista aâ”œÂ®rea Parque Grande 1964', 'Vista aâ”œÂ®rea del parque Primo de Rivera y el Cabezo Buenavista con el Jardâ”œÂ¡n de Invierno. Al fondo, el Hospital Militar. Mâ”œÃ­s al fondo, el Acampo Casellas y Valdespartera, al suroeste de la ciudad. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œÂ®.', 1964, 1964, 1964, 'Anos 60', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21695070983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21695070983.webp', 'https://www.flickr.com/photos/zaragozaantigua/21695070983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23262, 'Ctra. de Madrid 1913', 'Imagen capturada junto al arbolado cauce de la acequia de la Romareda Baja, o del Boquerazo, en el tramo paralelo a la carretera de Madrid a Francia, que queda a espaldas del fotâ”œâ”‚grafo, delimitado entre la calle del Trovador, hacia la izquierda, y el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n, hacia la derecha. Al fondo, despejada explanada de acceso al castillo de la Aljaferâ”œÂ¡a, habilitado como dependencia cuartelera del Ejâ”œÂ®rcito. Esta caudalosa acequia hacia la derecha surtâ”œÂ¡a luego la huerta de los conventos de Santa Inâ”œÂ®s, de las Carmelitas Descalzas de San Josâ”œÂ® o Fecetas, y de Santa Lucâ”œÂ¡a, ademâ”œÃ­s de al lavadero de la Sierra de Agua, ya en la calle del Veintinueve de Septiembre, para terminar derivando en la acequia Mayor de la Almozara, un poco antes de su desemboque en el râ”œÂ¡o Ebro.', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.65598400, -0.89459100, '0101000020E61000004F78094E7DA0ECBF8159A148F7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48576393371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48576393371.webp', 'https://www.flickr.com/photos/zaragozaantigua/48576393371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23265, 'Aljaferâ”œÂ¡a c.1895', 'Imagen centrada en el castillo de la Aljaferâ”œÂ¡a habilitado como cuartel del ramo de la Guerra para acoger al regimiento de infanterâ”œÂ¡a del Infante Nâ”¬â•‘ 5 y el regimineto de Gerona Nâ”¬â•‘ 22. En primer tâ”œÂ®rmino, curso al aire de la acequia Baja de la Romareda, tambiâ”œÂ®n denominada del "Boquerazo" que, proveniente del camino de la Mosquetera, y tras cruzar soterrada la carretera de Madrid a Francia continâ”œâ•‘a hacia la derecha para cruzar el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n y dirigirse hacia los conventos de Santa Inâ”œÂ®s y de las Fecetas.', 1895, 1895, 1895, 'Siglo XIX', 'DELICIAS', 41.65587900, -0.89551400, '0101000020E61000004D86E3F90CA8ECBF0C91D3D7F3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54162313102.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54162313102.webp', 'https://www.flickr.com/photos/zaragozaantigua/54162313102/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23269, 'La Aljaferâ”œÂ¡a 1808', '"Baterâ”œÂ¡a del Portillo. Donde, al ver sus defensores caer muertos o heridos sin quedar quien sirviese la artillerâ”œÂ¡a, la intrâ”œÂ®pida Agustina Aragâ”œâ”‚n, saltando por encima de los cadâ”œÃ­veres arrebatâ”œâ”‚ la mecha de manos de un artillero que acababa de expirar; y haciendo fuego con gallarda bizarrâ”œÂ¡a atajâ”œâ”‚ el â”œÂ¡mpetu furioso de los enemigos en el ataque del 4 de julio". Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. Al fondo vemos la Aljaferâ”œÂ¡a, a la derecha de una torre agrâ”œÂ¡cola. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65613800, -0.89280000, '0101000020E610000036CD3B4ED191ECBFD8D47954FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15244962776.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15244962776.webp', 'https://www.flickr.com/photos/zaragozaantigua/15244962776/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23438, 'La Aljaferâ”œÂ¡a 1983', 'Excavaciâ”œâ”‚n en La Aljaferâ”œÂ¡a para recuperar el foso de Tiburzio Spanochi de finales del siglo XVI. A la izquierda, el recreado paâ”œâ–’o oriental palaciego por el que se accedâ”œÂ¡a a la nueva sede de las Cortes de Aragâ”œâ”‚n. En primer tâ”œÂ®rmino, camiones aparcados en esta zona con fuerte presencia del sector del transporte interurbano de mercancâ”œÂ¡as. Al fondo, la industrial Quâ”œÂ¡mica y el barrio de La Almozara. La foto estâ”œÃ­ tomada desde cierta altura en el inmueble del nâ”¬â•‘ 33 de la avenida de Madrid.', 1983, 1983, 1983, 'Anos 80', 'DELICIAS', 41.65626900, -0.89677100, '0101000020E6100000F609A01859B2ECBF7730629F00D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871802947.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871802947.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871802947/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23439, 'Panorâ”œÃ­mica Aljaferâ”œÂ¡a 1973', 'El castillo de la Aljaferâ”œÂ¡a centra esta vista en altura capturada desde el reciente bloque del nâ”¬â•‘ 31 de la avenida de Madrid. Se estaba realizando, segâ”œâ•‘n el proyecto de Francisco â”œÃ¬â”œâ–’iguez, la reconstrucciâ”œâ”‚n de la puerta de acceso, los dos torreones que la flanquean y el resto de cubos del lienzo oriental de la muralla, con el torreâ”œâ”‚n de â”œÃ­ngulo y su enlace con la torre del Homenaje. El proceso de restauraciâ”œâ”‚n se prolongâ”œâ”‚ durante dâ”œÂ®cadas, desde que ese arquitecto lo emprendiese en 1947 y hasta su muerte en 1982. El Ayuntamiento, propietario del inmueble desde 1978, lo cediâ”œâ”‚ en 1984 a las Cortes de Aragâ”œâ”‚n para establecer allâ”œÂ¡ su sede. En la panorâ”œÃ­mica y de izquierda a derecha: el paso a nivel del ferrocarril y la avenida de Madrid, que seâ”œâ–’alan el acceso hacia el populoso barrio de Las Delicias; el entorno del palacio de la Aljaferâ”œÂ¡a, que conserva varias construcciones de carâ”œÃ­cter militar, e incluye la inevitable explanada como aparcamiento de camiones; las naves de la Industrial Quâ”œÂ¡mica de Zaragoza y las vâ”œÂ¡as del ferrocarril. Al fondo van creciendo altas edificaciones en el barrio de La Almozara.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65551900, -0.89550300, '0101000020E610000053094FE8F5A7ECBF0C74ED0BE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875982386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875982386.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875982386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23447, 'La Aljaferâ”œÂ¡a 1593', 'Dibujo de la Aljaferâ”œÂ¡a de Zaragoza, en la parte de Levante. Tiburcio Spanochi, 1593. Archivo General de Simancas, Ministerio de Cultura de Espaâ”œâ–’a. "Este singular edificio sufriâ”œâ”‚ a lo largo de nueve siglos una compleja metamorfosis que lo presenta como un crisol de culturas y hechos histâ”œâ”‚ricos. Los mayores cambios se producen en la Edad Moderna. Se destina a sede y prisiâ”œâ”‚n del Tribunal del Santo Oficio. Tras las alteraciones de Aragâ”œâ”‚n de 1591, Felipe II propone al ingeniero Tiburcio Spanochi su fortificaciâ”œâ”‚n y transformaciâ”œâ”‚n en ciudadela. El proyecto se realiza en 1593 rodeando el palacio de un foso con baluartes. La fortaleza se construye de argamasa y ladrillos con cadenas de sillares en las esquinas, siendo las dos puertas, sobre todo la principal de este dibujo, las que concentran la decoraciâ”œâ”‚n. Su funciâ”œâ”‚n palatina darâ”œÃ­ paso al uso militar que mantuvo hasta mediados del siglo XX."', 1593, 1593, 1593, 'Siglo XIX', 'DELICIAS', 41.65651600, -0.89631200, '0101000020E61000003065E08096AEECBF7FA65EB708D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15061057811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15061057811.webp', 'https://www.flickr.com/photos/zaragozaantigua/15061057811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23453, 'La Aljaferâ”œÂ¡a 1998', 'Aâ”œÂ®rea vista de la ciudad con el Palacio de la Aljaferâ”œÂ¡a como hito fundamental, visto desde el oeste. Tras la decisiâ”œâ”‚n tomada en 1985 de ubicar aquâ”œÂ¡ a las Cortes de Aragâ”œâ”‚n, la imagen del edificio se corresponde con las labores de adecuaciâ”œâ”‚n del mismo a funciones y utilidades para las que no estaba pensado, con una compleja cohabitaciâ”œâ”‚n de espacios institucionales y museâ”œÂ¡sticos, que se inclinan siempre en beneficio de los corporativos intereses de quienes estâ”œÃ­n detrâ”œÃ­s del foso. Fuente visual: "La Aljaferâ”œÂ¡a", Cortes de Aragâ”œâ”‚n, 1998.', 1998, 1998, 1998, 'Anos 90', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15319745870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15319745870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15319745870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23455, 'La Aljaferâ”œÂ¡a 1973', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Junio 1973. Imagen del Castillo de la Aljaferâ”œÂ¡a, cuando se estaba realizando, segâ”œâ•‘n el proyecto de Francisco â”œÃ¬â”œâ–’iguez, la reconstrucciâ”œâ”‚n de la puerta de acceso de la muralla, de los dos torreones que la flanquean y del resto de la muralla del lienzo este, con el torreâ”œâ”‚n de â”œÃ­ngulo y su enlace con la torre del Homenaje. Para la reconstrucciâ”œâ”‚n de los torreones cilâ”œÂ¡ndricos, â”œÃ¬â”œâ–’iguez tuvo en cuenta los alzados de Spanochi de 1593 y los alzados y plantas de Miguel Marâ”œÂ¡n de 1757. Las obras de intervenciâ”œâ”‚n en la Aljaferâ”œÂ¡a, en sus diversas fases, se extendieron desde 1955 hasta 1997.', 1973, 1973, 1973, 'Anos 70', 'DELICIAS', 41.65671300, -0.89653300, '0101000020E6100000D21C59F965B0ECBFD5EDEC2B0FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380138162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380138162.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380138162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23467, 'La Aljaferâ”œÂ¡a 1860', 'Vista de la fachada principal del palacio de la Aljaferâ”œÂ¡a. Detrâ”œÃ­s sobresalen la torre del Trovador y la de la capilla de San Martâ”œÂ¡n. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œÃ¼lbum de Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Colecciâ”œâ”‚n Mariano Martâ”œÂ¡n Casalderrey. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'DELICIAS', 41.65654200, -0.89635300, '0101000020E6100000D47C957CECAEECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28489798401.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28489798401.webp', 'https://www.flickr.com/photos/zaragozaantigua/28489798401/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23470, 'La Aljaferâ”œÂ¡a 1593', 'Maqueta elaborada por Ramiro Hernâ”œÃ­ndez con el aspecto del palacio de La Aljaferâ”œÂ¡a en 1593, tras su fortificaciâ”œâ”‚n por orden de Felipe II. Fuente: Heraldo de Aragâ”œâ”‚n.', 1593, 1593, 1593, 'Siglo XIX', 'DELICIAS', 41.65660300, -0.89699900, '0101000020E6100000376E313F37B4ECBF4DBA2D910BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31440509833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31440509833.webp', 'https://www.flickr.com/photos/zaragozaantigua/31440509833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23476, 'La Aljaferâ”œÂ¡a 1986', 'Foto: Juan Gonzâ”œÃ­lez Misis. 10 de mayo de 1986. El prâ”œÂ¡ncipe Felipe de Borbâ”œâ”‚n se afana en la colocaciâ”œâ”‚n de la primera piedra de las obras de acondicionamiento del palacio de la Aljaferâ”œÂ¡a como futura sede de las Cortes de Aragâ”œâ”‚n. Fuente: Heraldo de Aragâ”œâ”‚n.', 1986, 1986, 1986, 'Anos 80', 'DELICIAS', 41.65648500, -0.89700700, '0101000020E6100000ED0E290648B4ECBF44A852B307D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33499313435.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33499313435.webp', 'https://www.flickr.com/photos/zaragozaantigua/33499313435/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23696, 'Carmelitas Descalzos 1923', 'En 1835, los procesos desamortizadores desamortizaron a los PP. Carmelitas Descalzos del Convento de San Josâ”œÂ®, en el que llevaban casi desde 1594. Volvieron en febrero de 1897, a la casa-asilo para sacerdotes que el Arzobispo les prestâ”œâ”‚ en el barrio de Delicias. Allâ”œÂ¡ estuvieron hasta enero de 1946, en que se trasladaron a la nueva parroquia de la calle San Juan de la Cruz. Este edificio fue luego ocupado por el colegio de las Hijas de San Josâ”œÂ® y la escuela de San Valero hasta su derribo en los aâ”œâ–’os 80. En la imagen, la Casa-Asilo prestada para convento carmelita, sita en las inmediaciones del cuartel de la Aljaferâ”œÂ¡a, entre la carretera de Madrid y las vâ”œÂ¡as del ferrocarril, junto al Barrio de la Explanada. Su fachada mira hacia la Aljaferâ”œÂ¡a.', 1923, 1923, 1923, 'Anos 20', 'DELICIAS', 41.65538200, -0.90006300, '0101000020E610000065DEAAEB50CDECBF8C31B08EE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15519093557.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15519093557.webp', 'https://www.flickr.com/photos/zaragozaantigua/15519093557/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23697, 'Paso a nivel Delicias 1915', 'Archivo Municipal. Francisco Gâ”œâ”‚rriz (Donaciâ”œâ”‚n Palacio Fuenclara). 1915. "Retrato de grupo de niâ”œâ–’os". Imagen capturada en el paso a nivel de Delicias, antes de que fuera ensanchado. El tranvâ”œÂ¡a circulaba junto a la acera de enfrente. Poco trâ”œÃ­fico rodado, y sol.', 1915, 1915, 1915, 'Anos 10', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15583773786.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15583773786.webp', 'https://www.flickr.com/photos/zaragozaantigua/15583773786/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23699, 'Juan XXIII 1984', 'Imagen de la calle Juan XXIII capturada desde la entrada por la Avenida de Madrid, con visual (a la izquierda) de la casa-asilo para sacerdotes que el Arzobispo prestâ”œâ”‚ en el barrio de Delicias a los PP. Carmelitas Descalzos y que fue su base de operaciones desde febrero de 1897 hasta enero de 1944, en que se trasladaron a la nueva parroquia de la calle San Juan de la Cruz. A finales de los aâ”œâ–’os 80 del pasado siglo, el edificio fue piqueteado, y en su lugar se construyeron las nuevas instalaciones del IES "El Portillo", que se vino aquâ”œÂ¡ desde las antiguas instalaciones del Colegio de Maristas de San Vicente de Paâ”œâ•‘l. De esta forma, el IES queda justo enfrente del Colegio Pâ”œâ•‘blico Juan XXIII. Fuente visual: "Zaragoza, sus calles y su historia", HA, 1984.', 1984, 1984, 1984, 'Anos 80', 'DELICIAS', 41.65538200, -0.90006300, '0101000020E610000065DEAAEB50CDECBF8C31B08EE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16030415709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16030415709.webp', 'https://www.flickr.com/photos/zaragozaantigua/16030415709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23713, 'Paso a nivel Delicias 1913', '"Nuevo paso a nivel recientemente inaugurado en el Castillo de la Aljaferâ”œÂ¡a, de gran interâ”œÂ®s para la lâ”œÂ¡nea de Zaragoza-Navarra". En 1911, al objeto de reducir la peligrosidad del cruce transversal, y a nivel, de la carretera de Madrid y la lâ”œÂ¡nea de ferrocarril de Alsasua, el Ayuntamiento impulsâ”œâ”‚ la construcciâ”œâ”‚n de un paso subterrâ”œÃ­neo "mediante una trinchera suficiente para el paso de carros sin entorpecimiento y obstâ”œÃ­culos". Fue inaugurado en 1912. En la imagen, capturada desde la carretera de Madrid, con el cuartel de La Aljaferâ”œÂ¡a a la izquierda, vista de la trinchera del primer paso a nivel de las Delicias. Un buen nâ”œâ•‘meros de "tancredos", y entre ellos no faltan escolares del entorno, comprueban la firmeza del paso. Por abajo, peatones hacia Delicias. Al fondo, el â”œÃ­rea del Portillo. Fuente: Foto Marâ”œÂ¡n, diario "La Crâ”œâ”‚nica".', 1913, 1913, 1913, 'Anos 10', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25477385870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25477385870.webp', 'https://www.flickr.com/photos/zaragozaantigua/25477385870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23735, 'Paso a nivel Delicias 1912', 'Imagen de las obras de construcciâ”œâ”‚n del nuevo paso a nivel ferroviario de la lâ”œÂ¡nea de Madrid-Zaragoza (p.k. 340,436), sobre el paso inferior de la carretera de Madrid a Francia. En 1911, y al objeto de reducir la creciente peligrosidad del cruce a nivel de la carretera y la lâ”œÂ¡nea de ferrocarril, el Ayuntamiento impulsâ”œâ”‚ la construcciâ”œâ”‚n de este paso subterrâ”œÃ­neo en forma de "trinchera suficiente para el paso de carros sin entorpecimiento y obstâ”œÃ­culos". En este excepcional caso, la trinchera o zanja no era para uso ferroviario. La imagen ha sido capturada desde la carretera de Madrid, con el cuartel de La Aljaferâ”œÂ¡a a la izquierda y fuera de plano, y algunos inmuebles recayentes a la carretera, a la derecha. Al fondo, ascendente rampa hacia el â”œÃ­rea del Portillo. Desde su privilegiada posiciâ”œâ”‚n en la parte superior, los "tancredos" de turno observan el progreso de las obras.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65526600, -0.89796000, '0101000020E610000095B7239C16BCECBF22179CC1DFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48876001528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48876001528.webp', 'https://www.flickr.com/photos/zaragozaantigua/48876001528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23736, 'Ctra. de Madrid c.1893', 'Interesante y poco frecuente imagen capturada desde la Casa-Asilo de Sacerdotes propiedad del Arzobispado sita en el camino de Herederos paralelo a la vâ”œÂ¡a del ferrocarril de Madrid. En primer tâ”œÂ®rmino, el paso a nivel ferroviario de las lâ”œÂ¡nea de Madrid que, en su camino hacia la estaciâ”œâ”‚n de los directos, se cruza con la carretera de Madrid a Francia. A la derecha, el barrio de la Explanada, que culmina al fondo en la gran estructura del Hospicio Provincial y la câ”œâ•‘pula de San Ildefonso. Hacia la izquierda, la iglesia del Portillo, de la que casi emergen la torre de San Pablo Apâ”œâ”‚stol y la recrecida torre de Santiago del templo del Pilar. Algo mâ”œÃ­s hacia la derecha y al fondo, la torre y cimborrio de la Seo, y la Torre Nueva demediada y en inexorable proceso de derribo. Ademâ”œÃ­s pueden verse la torre de Santa Marâ”œÂ¡a Magdalena, San Gil Abad, etc. En 1896 esta Casa-Asilo serâ”œÂ¡a cedida a la Orden de los Carmelitas, que la habilitarâ”œÂ¡an como provisional convento durante varias dâ”œÂ®cadas.', 1893, 1893, 1893, 'Siglo XIX', 'DELICIAS', 41.65530200, -0.89832500, '0101000020E610000002BC051214BFECBF6F8099EFE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49050784196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49050784196.webp', 'https://www.flickr.com/photos/zaragozaantigua/49050784196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23739, 'Paso de Delicias 1923', 'Imagen del paso a nivel ferroviario de Delicias desde la avenida de Madrid. A la izquierda, inmuebles de los nâ”œâ•‘meros 49-55, donde destaca el aserradero de maderas de Gimâ”œÂ®nez y Hernâ”œÃ­ndez. A la derecha, operarios laborando en la torre de agujas y la fachada del convento de los carmelitas descalzos de san Josâ”œÂ®. Al fondo, el barrio de las Delicias. En primer tâ”œÂ®rmino, terroso aspecto de la avenida con la vâ”œÂ¡a â”œâ•‘nica de la lâ”œÂ¡nea Delicias del tranvâ”œÂ¡a, que en 1927 serâ”œÂ¡a desdoblada.', 1923, 1923, 1923, 'Anos 20', 'DELICIAS', 41.65532600, -0.89777800, '0101000020E61000006A2FA2ED98BAECBFF81BEDB8E1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51284102729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51284102729.webp', 'https://www.flickr.com/photos/zaragozaantigua/51284102729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23917, 'Vista desde El Portillo c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1874-1877. "Vista general desde el Portillo". Panorâ”œÃ­mica pergeâ”œâ–’ada para la ocasiâ”œâ”‚n, en una composiciâ”œâ”‚n inâ”œÂ®dita, democrâ”œÃ­tica, cientâ”œÂ¡fica y popular, generada en los laboratorios del', 1877, 1877, 1877, 'Siglo XIX', 'DELICIAS', 41.65588700, -0.89301400, '0101000020E610000038D89B189293ECBF8F6FEF1AF4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14832053848.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14832053848.webp', 'https://www.flickr.com/photos/zaragozaantigua/14832053848/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23926, 'Plaza del Portillo 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Marzo 1966. Imagen de la celebraciâ”œâ”‚n de la Fiesta de la Guardia Municipal en la plaza del Portillo. Detrâ”œÃ­s de la Policâ”œÂ¡a Montada de Saldudâ”œÃ­, la iglesia del Portillo (con su recuerdo al "Ausente"), y las viviendas a ella anexas, en lo que hoy es calle Monseâ”œâ–’or â”œÃ´scar Ataâ”œâ•‘lfo Romero, y aledaâ”œâ–’os.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65564900, -0.89266600, '0101000020E61000004E098849B890ECBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15716569715.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15716569715.webp', 'https://www.flickr.com/photos/zaragozaantigua/15716569715/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23927, 'Agustina de Aragâ”œâ”‚n 1808', 'Litografâ”œÂ¡a de Pâ”œÂ®rez, 1873. Ilustraciâ”œâ”‚n sobre la câ”œÂ®lebre reusina Agustina Zaragoza (1786-1857), que segâ”œâ•‘n la leyenda, prendiâ”œâ”‚ fuego a un caâ”œâ–’â”œâ”‚n a los 22 aâ”œâ–’os en la puerta del Portillo de Zaragoza, ante el ataque francâ”œÂ®s durante los sitios. Fuente: Los Niâ”œâ–’os, revista de educaciâ”œâ”‚n y recreo, octubre de 1873.', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65606200, -0.89276300, '0101000020E6100000EC8502B68391ECBFFD12F1D6F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20040832241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20040832241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20040832241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23930, 'Calle Jesâ”œâ•‘s Muro 1968', '"Discurso durante la inauguraciâ”œâ”‚n de la calle Jesâ”œâ•‘s Muro." La apertura de un nuevo vial entre la plaza del Portillo y el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n dio pie a que el Ayuntamiento decidiera ponerle el nombre del recientemente fallecido Jesâ”œâ•‘s Muro Sevilla, singularizando en el correspondiente azulejo su responsabilidad como jefe de la Falange zaragozana el 18 de julio de 1936. En la imagen, nocturna captura del acto oficial de inauguraciâ”œâ”‚n de la nueva calle, con presencia de miembros de la corporaciâ”œâ”‚n municipal, con el alcalde Cesâ”œÃ­reo Alierta al frente, y "camisas viejas" (+ â”œâ”‚ -) de la Falange local. A los micrâ”œâ”‚fonos, Radio Zaragoza. Al fondo, entre las tinieblas, restos del Cuartel del Cid (izquierda), y la câ”œâ•‘pula y torres del Hogar Pignatelli. Esta calle serâ”œÃ­ redenominada "Marie Curie" en el aâ”œâ–’o 2009.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65489500, -0.89331300, '0101000020E6100000C8EE02250596ECBF2FA86F99D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22480873808.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22480873808.webp', 'https://www.flickr.com/photos/zaragozaantigua/22480873808/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23931, 'Plaza del Portillo 1968', 'Imagen capturada durante la celebraciâ”œâ”‚n oficial del celestial patronazgo ejercido por Nuestra Seâ”œâ–’ora del Portillo sobre la Guardia Municipal de la ciudad, como tradicionalmente venâ”œÂ¡a haciâ”œÂ®ndose desde los aâ”œâ–’os 40 (de ese mismo siglo XX). El lugar son las inmediaciones a la iglesia del Portillo, que queda a la derecha de la imagen. Como fondo escâ”œÂ®nico, el antiguo Cuartel de Caballerâ”œÂ¡a del Cid, desmilitarizado tras la primera fase de la "Operaciâ”œâ”‚n Cuarteles", que ya ha sido limpiamente seccionado para posibilitar la apertura de un nuevo vial entre la plaza del Portillo y el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n (al fondo), vial al que el Ayuntamiento decidiâ”œâ”‚ ponerle el nombre del recientemente fallecido Jesâ”œâ•‘s Muro Sevilla, jefe de la Falange zaragozana el 18 de julio de 1936. En el suelo, entre adoquines, perdura el tendido viario de la desmantelada lâ”œÂ¡nea tranviaria de Madrid. A la derecha, el edificio del nâ”¬â•‘ 5 de la plaza del Portillo. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal)', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65499200, -0.89245500, '0101000020E610000090DAC4C9FD8EECBF219221C7D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23359946661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23359946661.webp', 'https://www.flickr.com/photos/zaragozaantigua/23359946661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23941, 'Plaza del Portillo 1892', 'Imagen capturada desde la altura de la iglesia del Portillo, y centrada en el entorno de esa arbolada plaza. Tras ella, el antiguo coso de la Misericordia, y a su derecha, la Casa Inclusa, y el cuartel de caballerâ”œÂ¡a del Cid. A la izquierda, la calle de Pignatelli y el cuartel de Ingenieros de Sangenis. De fondo, el impresionante Hospicio Provincial, con su neobizantina câ”œâ•‘pula. Hemos volteado horizontalmente la original imagen, y asâ”œÂ¡ se ven mâ”œÃ­s las cosas en su sitio. Fuente visual: Estudio Coyne, AHPZ.', 1892, 1892, 1892, 'Siglo XIX', 'DELICIAS', 41.65564700, -0.89232100, '0101000020E6100000A91611C5E48DECBF3A5CAB3DECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30802095414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30802095414.webp', 'https://www.flickr.com/photos/zaragozaantigua/30802095414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23942, 'Portillo 1808', '"La heroâ”œÂ¡na de Zaragoza". â”œÃ´leo sobre lienzo, Marcos Hirâ”œÃ­ldez Acosta, 1871. Representaciâ”œâ”‚n del momento en que Agustina de Aragâ”œâ”‚n prende la mecha de un caâ”œâ–’â”œâ”‚n contra el ejâ”œÂ®rcito francâ”œÂ®s, en los Sitios de Zaragoza. Al fondo a la derecha, la entrada a la ciudad por la puerta del Portillo, anexa a la iglesia homâ”œâ”‚nima, fuera de cuadro. Fuente: web.dpz.es/arscatalogi.es/', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65614900, -0.89383200, '0101000020E6100000E2C80391459AECBFCC26C0B0FCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32103983833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32103983833.webp', 'https://www.flickr.com/photos/zaragozaantigua/32103983833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23944, 'El Portillo 1808', '"La defensa de Zaragoza"; â”œâ”‚leo sobre lienzo, David Wilkie, 1828. Agustina de Aragâ”œâ”‚n comparece ante su mâ”œÂ¡tico caâ”œâ–’â”œâ”‚n, presta a dispararlo hacia las afueras de Zaragoza contra el ejâ”œÂ®rcito francâ”œÂ®s. Tras ella, el Portillo propiamente dicho. Fuente: WIkimedia Commons.', 1808, 1808, 1808, 'Siglo XIX', 'DELICIAS', 41.65622400, -0.89352900, '0101000020E6100000F8E12021CA97ECBFD76CE525FFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40384270754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40384270754.webp', 'https://www.flickr.com/photos/zaragozaantigua/40384270754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23973, 'Pl. del Portillo c.1962', 'Archivo Municipal de Zaragoza. Archivo fotogrâ”œÃ­fico Editorial Arribas (EDIVIS). Aâ”œâ–’os 60. "Plaza de Toros." Un primer Coso Taurino fue mandado construir por Ramâ”œâ”‚n Pignatelli para conseguir ingresos con que mantener la Casa de la Misericordia. Inaugurado en 1764, era en madera, luego ladrillo, y en 1895, en piedra. La gran reforma de 1916, dirigida por Martinez de Ubago y Miguel Angel Navarro, le dio el aspecto actual. En la imagen, vista panorâ”œÃ­mica de la plaza del Portillo, la plaza de toros, el Cuartel del Cid, La Casa de la Misericordia, la Maternidad e Inclusa de la DPZ, y las casas de militares del Paseo de Mâ”¬Â¬ Agustâ”œÂ¡n.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65537000, -0.89228600, '0101000020E61000008DB7955E9B8DECBFC763062AE3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15181301378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15181301378.webp', 'https://www.flickr.com/photos/zaragozaantigua/15181301378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24171, 'Paso elevado Delicias 1989', 'Construcciâ”œâ”‚n del paso elevado sobre las vâ”œÂ¡as del tren y la avenida de Madrid. Fuente: Nuestra Zaragoza, agosto 1989.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65510500, -0.89781300, '0101000020E6100000868E1D54E2BAECBF19390B7BDAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14844870208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14844870208.webp', 'https://www.flickr.com/photos/zaragozaantigua/14844870208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24174, 'Aljaferâ”œÂ¡a: vâ”œÂ¡as al aire 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 02/05/1974. Vista desde la calle Juan XXIII de un Talgo circulando en direcciâ”œâ”‚n a la Estaciâ”œâ”‚n del Portillo (hacia la derecha). Detrâ”œÃ­s sobresale uno de los cuadrangulares torreones de la Aljaferâ”œÂ¡a, el que da a la Avenida de Madrid. Mâ”œÃ­s al fondo, a la derecha, sobresalen las dos torrecillas de la iglesia de la Real Casa de la Misericordia. La seâ”œâ–’ora pasando por las vâ”œÂ¡as, yendo a visitar a su prima del Barrio de la Quâ”œÂ¡mica.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65640100, -0.90016000, '0101000020E6100000035B25581CCEECBFE607AEF204D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907637952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907637952.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907637952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24176, 'Paso a nivel Delicias c.1966', '"Paso a desnivel". Colecciâ”œâ”‚n Paco Boisset Locomotora a vapor tirando de un convoy en el paso a nivel de Las Delicias, viviendo de la estaciâ”œâ”‚n Campo Sepulcro (al fondo). Por debajo pasa la avenida de Madrid.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.65518200, -0.89805100, '0101000020E6100000AB7B6473D5BCECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15007240298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15007240298.webp', 'https://www.flickr.com/photos/zaragozaantigua/15007240298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
