INSERT INTO public.photos VALUES (24203, 'Tâ”œâ•‘nel de cercanâ”œÂ¡as 2007', 'Foto: â”œÃ¼lvaro Calvo. Obras de cubrimiento del tâ”œâ•‘nel ferroviario de cercanâ”œÂ¡as bajo la desmantelada plaza de la Ciudadanâ”œÂ¡a (abajo), en septiembre de 2007. Unirâ”œÃ­ la estaciâ”œâ”‚n Delicias con la futura del Portillo (a la espalda). Hacia el fondo, la futura avenida Ciudad de Soria, Esta obra tambiâ”œÂ®n incluyâ”œâ”‚ un tâ”œâ•‘nel carretero "de salida râ”œÃ­pida de la ciudad", que tras ser construido no fue puesto en servicio. A la izquierda, edificios en la calle Juan XIII. Fuente: Heraldo de Aragâ”œâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'DELICIAS', 41.65573700, -0.89867300, '0101000020E6100000EC8A19E1EDC1ECBF7AE3A430EFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32359189121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32359189121.webp', 'https://www.flickr.com/photos/zaragozaantigua/32359189121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24204, 'Vista Delicias 1997', 'Vista aâ”œÂ®rea centrada en el paso elevado de Las Delicias, que salvâ”œâ”‚ entre 1989 y 2001 el trâ”œÃ­nsito de la avenida de Madrid sobre las vâ”œÂ¡as del ferrocarril y la autopista. Abajo, instalaciones de la estaciâ”œâ”‚n del Portillo y de Averly. Al fondo a la derecha, el meandro de Ranillas. Fuente: Colecciâ”œâ”‚n particular.', 1997, 1997, 1997, 'Anos 90', 'DELICIAS', 41.65528300, -0.89803700, '0101000020E61000006C223317B8BCECBFF84F3750E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32645266985.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32645266985.webp', 'https://www.flickr.com/photos/zaragozaantigua/32645266985/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24361, 'Torre de San Martâ”œÂ¡n 1964', 'Fototeca Universidad de Sevilla. Antonio Palau. Agosto de 1964. "Aljaferâ”œÂ¡a: torre". Muy interesante imagen de la torre de la iglesia de San Martâ”œÂ¡n enclavada en el interior del Cuartel de la Aljaferâ”œÂ¡a. Construida en formas y modas tardo-barrocas, casi neoclâ”œÃ­sicas, sobre un previo alminar modificado tras la conquista cristiana de 1118 (el cuerpo inferior de la imagen). La torre fue desmochada durante los conflictos bâ”œÂ®licos de los aâ”œâ–’os 1808-1809, y luego restaurada. Llegâ”œâ”‚ en el estado que muestra la imagen hasta que la intervenciâ”œâ”‚n y restauraciâ”œâ”‚n del Palacio, en la segunda mitad del siglo XX, eliminâ”œâ”‚ los aâ”œâ–’adidos barrocos, dejando despejado el previo alminar. La imagen ha sido tomada desde una ventana del patio de San Martâ”œÂ¡n, el principal acceso al interior del Palacio. Fuente visual: fototeca.us.es/imagen.jsp?id=25891&tipo=v&elto=16...', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65677400, -0.89664700, '0101000020E6100000F2CEA10C55B1ECBF7A6EA12B11D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15013872864.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15013872864.webp', 'https://www.flickr.com/photos/zaragozaantigua/15013872864/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
