INSERT INTO public.photos VALUES (24417, 'Aljaferâ”œÂ¡a 1890', 'Imagen del mihrab, con orientaciâ”œâ”‚n sureste, de la mezquita poligonal ubicada en al Qasr al-Ja''fariyya (palacio de Abâ”œâ•— Ja''far o Aljaferâ”œÂ¡a), del siglo XI, en su estado como dependencia cuartelera a finales del siglo XIX. Fuente visual: "Detalle del interior de la mezquita - Palacio de la Aljaferâ”œÂ¡a", fototipia de Joarizti y Mariezcurrena, en Ã”Ã‡Â£Zaragoza Artâ”œÂ¡stica, Monumental e Histâ”œâ”‚ricaÃ”Ã‡Ã˜, Anselmo y Pedro Gascâ”œâ”‚n de Gotor (1890-91).', 1890, 1890, 1890, 'Siglo XIX', 'DELICIAS', 41.65666700, -0.89676800, '0101000020E6100000B22D03CE52B2ECBF64AE0CAA0DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34305565736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34305565736.webp', 'https://www.flickr.com/photos/zaragozaantigua/34305565736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24509, 'Jabones Nicolâ”œÃ­s c.1955', 'Vista de la entrada de la antigua fâ”œÃ­brica de Jabones Nicolâ”œÃ­s, poco despuâ”œÂ®s de que este mismo espacio fuese ocupado por la fâ”œÃ­brica de muebles de alta gama Simâ”œâ”‚n Loscertales Bona, en la calle Aljaferâ”œÂ¡a, donde terminaba la calle Comandante Rodrâ”œÂ¡guez de Câ”œâ”‚rdoba (desde 2009, Sebastiâ”œÃ­n Banzo Urrea).', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65708700, -0.89476500, '0101000020E6100000C45F9335EAA1ECBF39D0436D1BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32061267736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32061267736.webp', 'https://www.flickr.com/photos/zaragozaantigua/32061267736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
