INSERT INTO public.photos VALUES (24559, 'La Aljaferâ”œÂ¡a 1983', 'Antiguo palacio de la Aljaferâ”œÂ¡a durante las obras de restauraciâ”œâ”‚n iniciadas en 1947 por Francisco â”œÃ¬â”œâ–’iguez. Al fondo, a la izquierda, la avenida de Madrid. Fuente visual: Foto Leonardo Pâ”œÂ®rez Obis, donada por â”œÃ¼ngel Hernâ”œÃ­ndez Mostajo para www.rafaelcastillejo.com', 1983, 1983, 1983, 'Anos 80', 'DELICIAS', 41.65665500, -0.89592400, '0101000020E6100000B972F6CE68ABECBFA0E062450DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22725003887.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22725003887.webp', 'https://www.flickr.com/photos/zaragozaantigua/22725003887/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24560, 'La Aljaferâ”œÂ¡a 1627', 'Plano de la Aljaferâ”œÂ¡a de Zaragoza, con indicaciâ”œâ”‚n del lugar que ocupaba la sede de la Inquisiciâ”œâ”‚n, 1627. Este plano fue datado por Pedro I. Sobradiel en 2009. Incluye, superpuestos, unos papeles con las fachadas del patio de San Martâ”œÂ¡n, lugar que ocupaba la Inquisiciâ”œâ”‚n tras la fortificaciâ”œâ”‚n del edificio en 1593, habiendo sido anteriormente todo el edificio propiedad de ese tribunal. Fuente: servicios3.aragon.es/bva/i18n/catalogo_imagenes/grupo.cmd...', 1627, 1627, 1627, 'Siglo XIX', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23808862353.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23808862353.webp', 'https://www.flickr.com/photos/zaragozaantigua/23808862353/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24561, 'La Aljaferâ”œÂ¡a 1708', '"Plano del castillo de la Inquisiciâ”œâ”‚n, cerca de Zaragoza, capital del reino de Aragâ”œâ”‚n en Espaâ”œâ–’a, en el estado en que estaba en 1708", por el ingeniero francâ”œÂ®s Claude Massâ”œÂ®. Se trata de uno de los varios proyectos teâ”œâ”‚ricos de fortificaciâ”œâ”‚n del castillo de la Aljaferâ”œÂ¡a durante la guerra de Sucesiâ”œâ”‚n espaâ”œâ–’ola. Fuente visual: Pedro I. Sobradiel, El castillo de la Aljaferâ”œÂ¡a: 1600-1800. de medieval a ilustrado, IEIOP, Zaragoza, 2009.', 1708, 1708, 1708, 'Siglo XIX', 'DELICIAS', 41.65656600, -0.89697300, '0101000020E6100000E8A38CB800B4ECBF30D5CC5A0AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24118516037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24118516037.webp', 'https://www.flickr.com/photos/zaragozaantigua/24118516037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24562, 'La Aljaferâ”œÂ¡a 1592', '"Traza del castillo que se ha de hacer en la Aljaferâ”œÂ¡a de Zaragoza", Tiburcio Spanochi, 1592. En 1592, Felipe II proyectâ”œâ”‚ varias obras de fortificaciâ”œâ”‚n de la ciudad de Zaragoza, a raâ”œÂ¡z de los altercados sucedidos desde 1591. De todas ellas, sâ”œâ”‚lo se realizâ”œâ”‚ la transformaciâ”œâ”‚n del Palacio de la Aljaferâ”œÂ¡a en castillo fortificado. En el plano, la Aljaferâ”œÂ¡a, el râ”œÂ¡o Ebro, la Puerta Sancho, la Puerta del Portillo y la iglesia del Portillo. Fuente: Archivo General de Simancas.', 1592, 1592, 1592, 'Siglo XIX', 'DELICIAS', 41.65650600, -0.89697200, '0101000020E6100000D1AFAD9FFEB3ECBF5BD07B6308D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24352922561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24352922561.webp', 'https://www.flickr.com/photos/zaragozaantigua/24352922561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26070, 'Ferias 1963', 'Vista aâ”œÂ®rea capturada sobrevolando el recinto de la 23 Feria Nacional de Muestras, rodeado en esta ocasiâ”œâ”‚n de las atracciones del ferial instalado con motivo de las Fiestas del Pilar. Hacia el fondo, la plaza del Emperador Carlos V y el final del paseo de Fernando el Catâ”œâ”‚lico, justo donde se prolonga como paseo de Isabel la Catâ”œâ”‚lica.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.63770500, -0.90032000, '0101000020E61000003AE97DE36BCFECBF72BF4351A0D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50831255853.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50831255853.webp', 'https://www.flickr.com/photos/zaragozaantigua/50831255853/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24564, 'Motâ”œÂ¡n de Zaragoza 1591', 'Ã”Ã‡Â£Las alteraciones de Aragâ”œâ”‚n. Motâ”œÂ¡n de Zaragoza, 1591Ã”Ã‡Ã˜. Grabado del siglo XIX coloreado posteriormente. En 1591 se produjeron ciertas algaradas en las calles de Zaragoza, que la historiografâ”œÂ¡a dio en ubicar en diversos entornos urbanos. Uno de estos pretendidos motines habrâ”œÂ¡a tenido lugar en la Aljaferâ”œÂ¡a, donde fue trasladado Antonio Pâ”œÂ®rez provisionalmente; la ilustraciâ”œâ”‚n quizâ”œÃ­s pretende reflejar ese entorno, sin demasiado acierto. Fuente visual: www.alamy.es', 1591, 1591, 1591, 'Siglo XIX', 'DELICIAS', 41.65671000, -0.89669400, '0101000020E61000001F9F909DB7B1ECBF637AC2120FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41057293392.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41057293392.webp', 'https://www.flickr.com/photos/zaragozaantigua/41057293392/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24877, 'Plaza del Portillo 1910', 'AHPZ. Archivo Coyne. 1910. Chavales posando en las traseras del "Monumento a Agustina de Aragâ”œâ”‚n y la heroâ”œÂ¡nas de los Sitios", inaugurado recientemente en la Plaza del Portillo. Al fondo, el Coso de la Misericordia, que unos pocos aâ”œâ–’os despuâ”œÂ®s serâ”œÃ­ mudejarizado con la reforma de Navarro y Martâ”œÂ¡nez de Ubago.', 1910, 1910, 1910, 'Anos 10', 'DELICIAS', 41.65552700, -0.89237600, '0101000020E61000008B87F71C588EECBF8F52094FE8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14834430038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14834430038.webp', 'https://www.flickr.com/photos/zaragozaantigua/14834430038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24923, 'Plaza del Portillo 1908', 'Foto: Freudenthal. Inauguraciâ”œâ”‚n del monumento a Agustina de Aragâ”œâ”‚n en la plaza del Portillo, por parte de Alfonso XIII y Victoria Eugenia, el 29 de octubre de 1908. Al fondo, iglesia del Portillo. Fuente: La ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana, a travâ”œÂ®s de www.facebook.com/photo.php?fbid=1205203256182307&set=...', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65565200, -0.89243700, '0101000020E6100000F7B0170AD88EECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33245875235.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33245875235.webp', 'https://www.flickr.com/photos/zaragozaantigua/33245875235/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24926, 'Plaza del Portillo 1908', 'El escultor Mariano Benlliure, inspeccionando su monumento a Agustina de Aragâ”œâ”‚n en la plaza del Portillo, en octubre de 1908. Serâ”œÃ­ inaugurado por los reyes el 29 del mismo mes. Fuente: Foto Moya. Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65565200, -0.89243700, '0101000020E6100000F7B0170AD88EECBF4CC79C67ECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41188191021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41188191021.webp', 'https://www.flickr.com/photos/zaragozaantigua/41188191021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25098, 'Victoria Eugenia 1908', 'Foto: Goâ”œâ–’i. La reina Victoria Eugenia y su marido Alfonso XIII inauguran el monumento a Agustina de Aragâ”œâ”‚n en la plaza del Portillo, el 29 de octubre de 1908. Fuente: Diario ABC.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65569200, -0.89243500, '0101000020E6100000C9C859D8D38EECBFDA1F28B7EDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40292986515.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40292986515.webp', 'https://www.flickr.com/photos/zaragozaantigua/40292986515/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25103, 'Calle del Portillo 1908', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 33 del paseo de Marâ”œÂ¡a Agustâ”œÂ¡n y centrada en el cortejo del rey Alfonso XIII que, acompaâ”œâ–’ado del alcalde y de los infantes Fernando y Luis Alfonso y proveniente del coso de la Misericordia, se dirige al recinto de la Exposiciâ”œâ”‚n Hispano-Francesa para visitarlo. A la izquierda, los muros perimetrales de la gran huerta del convento de Santa Inâ”œÂ®s. A la derecha, la iglesia de Nuestra Seâ”œâ–’ora del Portillo. Al fondo y en el centro, inmueble de la antigua Casa de la Galera esquinera entre la calle de Santa Inâ”œÂ®s y la calle del Portillo. Al fondo y a la izquierda, vista parcial de la torre de San Pablo Apâ”œâ”‚stol, y la torre de la Seo algo mâ”œÃ­s a la derecha. En primer tâ”œÂ®rmino y sobre el firme, tendido de la lâ”œÂ¡nea de Madrid del tranvâ”œÂ¡a, curvea hacia la derecha y la estaciâ”œâ”‚n de Campo sepulcro o del Mediodâ”œÂ¡a. Esta fue la primera de las dos veces que el jefe del Estado acudiâ”œâ”‚ a Zaragoza este aâ”œâ–’o. Asâ”œÂ¡, el dâ”œÂ¡a 14 de junio, acudiâ”œâ”‚ para asistir a diversas celebraciones memorialistas en las que inaugurâ”œâ”‚ lâ”œÃ­pidas dedicadas a Josâ”œÂ® Palafox en la homâ”œâ”‚nima calle; al Tâ”œÂ¡o Jorge o Jorge Ibort en la homâ”œâ”‚nima calle del Arrabal; a Basilio Boggiero, Santiago Sas y el barâ”œâ”‚n de Warsage en el puente de Piedra; a Antonio de Torres en la calle de Don Jaime I; a la condesa de Bureta en la calle de la Torre Nueva; a Pedro Marâ”œÂ¡a Ric en la Audiencia Provincial; finalmente, el Monumento al Reducto del Pilar no pudo ser inaugurado porque no estaba terminado. Por la tarde, el Rey fue a la plaza de toros a ver al torero Lagartijo torear miuras. En el tercer toro y aprovechando que el Lagartijo recibiâ”œâ”‚ un varetazo, el Rey abandonâ”œâ”‚ la plaza para, como muestra la imagen, encaminarse hacia el recinto de la exposiciâ”œâ”‚n Hispano-Francesa.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65617600, -0.89360400, '0101000020E6100000A164726A6798ECBFC6353E93FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50629504571.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50629504571.webp', 'https://www.flickr.com/photos/zaragozaantigua/50629504571/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25855, 'Calle del Conde de Aranda c.1994', 'Desde el inmueble del nâ”¬â•‘ 126 de la calle del Conde Aranda recayente a la plaza del Portillo, un vistazo en altura al tramo final de esa calle centrado en el denso trâ”œÃ­fico direccionado hacia el estratâ”œÂ®gico cruce con el paseo de Marâ”œÂ¡a Agustâ”œÂ¡n y el arranque de la avenida de Madrid. Al fondo, solar en obra donde estuviera el antiguo nâ”¬â•‘ 83 de este paseo y el nâ”¬â•‘ 2 de la calle del Castillo, donde poco despuâ”œÂ®s se levantarâ”œÂ¡a el actual y chaflanero nâ”¬â•‘ 2 de esa calle.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65618400, -0.89330400, '0101000020E6100000FB592C45F295ECBF49145AD6FDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50497334301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50497334301.webp', 'https://www.flickr.com/photos/zaragozaantigua/50497334301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25897, 'Paseo Marâ”œÂ¡a Agustâ”œÂ¡n c.1955', 'Cuesta del tramo del paseo Marâ”œÂ¡a Agustâ”œÂ¡n entre la Puerta de Sancho y el Portillo (al fondo). Distintos medios de transporte, entre ellos un tranvâ”œÂ¡a de la lâ”œÂ¡nea 7 "Ayuntamiento-Portillo". Fuente: www.facebook.com/photo.php?fbid=1574816756079888&set=...', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65718000, -0.89336300, '0101000020E6100000399B8E006E96ECBFEACA67791ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15225868337.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15225868337.webp', 'https://www.flickr.com/photos/zaragozaantigua/15225868337/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25935, 'La Ajaferâ”œÂ¡a c.1956', 'Imagen capturada desde la altura del antiguo inmueble del nâ”¬â•‘ 21 de la avenida de Madrid, casi esquinero con el arranque de la calle del Trovador, y centrada en el cuartel de La Aljaferâ”œÂ¡a con el que confrontaba. En primer tâ”œÂ®rmino, remolque de una composiciâ”œâ”‚n tranviaria de la serie 100 en servicio en la lâ”œÂ¡nea 5 Torrero-Delicias encaminada hacia este barrio. Tras ella, jardines con que se habâ”œÂ¡an hermoseado los terraplenes de acceso al cuartel, del que emergen la mole de la torre del Trovador, y la torrecilla de la iglesia de San Martâ”œÂ¡n. A la derecha, instalaciones fabriles de la Industrial Quâ”œÂ¡mica de Zaragoza.', 1956, 1956, 1956, 'Anos 50', 'DELICIAS', 41.65595200, -0.89602900, '0101000020E61000000C90680245ACECBF76DF313CF6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49495637613.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49495637613.webp', 'https://www.flickr.com/photos/zaragozaantigua/49495637613/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22529, 'Cabezo de Buena Vista 1972', 'La serie de tranvâ”œÂ¡as "80" entrâ”œâ”‚ en servicio en 1933, aunque hasta 1937 quedaron en cocheras. Con un remolque jardinera, comenzâ”œâ”‚ ese aâ”œâ–’o en la lâ”œÂ¡nea 11 "Parque", y en 1947 es asignado a la Lâ”œÂ¡nea 5 "Torrero-Delicias", luego "Venecia-Delicias". En noviembre de 1971 esta Lâ”œÂ¡nea fue suprimida. Fue adquirido por el Ayuntamiento para instalarlo en el Cabezo de Buena Vista como Biblioteca Infantil, como recoge la imagen. En 1980 fue definitivamente desguazado. Fuente visual: www.flickr.com/photos/jhm0284/5812535645/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.63226000, -0.89374900, '0101000020E610000083A5BA809799ECBFD4484BE5EDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14705380058.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14705380058.webp', 'https://www.flickr.com/photos/zaragozaantigua/14705380058/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21485, 'Estaciâ”œâ”‚n de Cariâ”œâ–’ena 1926', '1926. La necesidad de contar con un ferrocarril por el que transportar la producciâ”œâ”‚n vitivinâ”œÂ¡cola de Cariâ”œâ–’ena para su exportaciâ”œâ”‚n a Francia, fue el principal motor de la creaciâ”œâ”‚n del ferrocarril de Cariâ”œâ–’ena a Zaragoza. Fue inaugurado el 10 de agosto de 1887, con un servicio regular de trenes consistente en dos convoyes mixtos diarios de ida y vuelta, que perdurarâ”œÂ¡an hasta 1933, aâ”œâ–’o en que esta lâ”œÂ¡nea fue clausurada y subsumida en la de Caminreal. Pese a su cercanâ”œÂ¡a a Campo Sepulcro, la conexiâ”œâ”‚n entre ambas estaciones era complicada, por la notable diferencia de altura entre una y otra. Hubo que trazar un amplio ramal de enlace entre el "Barrio de la Romareda" (actual calle Vicente Berdusâ”œÃ­n y Escoriaza y Fabro) y el "Barrio de La Explanada" (a la izquierda de la carretera de Madrid), hasta llegar a un muelle intercambiador cerca del Paso a Nivel de Delicias. En la imagen, estaciâ”œâ”‚n de Cariâ”œâ–’ena en Zaragoza, con un convoy mixto (plataformas para mercancâ”œÂ¡as+vagones de viajeros) tirado por la locomotora a vapor nâ”¬â•‘ 2, denominada "Pilar". Al fondo, el ampliado edificio central de la estaciâ”œâ”‚n, derribado a principios de los aâ”œâ–’os 50.', 1926, 1926, 1926, 'Anos 20', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14998663245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14998663245.webp', 'https://www.flickr.com/photos/zaragozaantigua/14998663245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21865, 'Calle del Moncayo 1933', 'Imagen capturada en la calle del Moncayo, una de las mâ”œÃ­s representativas del muy industrial barrio de Cariâ”œâ–’ena o de la Romareda, frente a la estaciâ”œâ”‚n de Campo Sepulcro, Mediodâ”œÂ¡a, Madrid, o MZA. A la izquierda, el emboque a la calle del Sol y una de las reconocibles torres gemelas de la fâ”œÃ­brica de chocolate de Orâ”œâ•‘s. A ambos lados de la arbolada calle, hotelitos e industrias varias. Al fondo, el arranque de la calle del Moncayo desde la avenida de Romareda, paralela al tendido ferroviario que hacia la derecha lleva a Barcelona, pasando junto a la cercana y reciâ”œÂ®n clausurada estaciâ”œâ”‚n de tren de Cariâ”œâ–’ena. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'DELICIAS', 41.65006200, -0.89600600, '0101000020E610000001A260C614ACECBFA92F4B3B35D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36400788246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36400788246.webp', 'https://www.flickr.com/photos/zaragozaantigua/36400788246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22301, 'Campo Sepulcro 1967', 'Archivo Municipal. Gerardo Sancho Ramo. Noviembre 1967. Imagen del mar de vâ”œÂ¡as de la estaciâ”œâ”‚n de tren Campo Sepulcro, a puento de pasar un convoy tirado por una nueva locomotora diesel. A la derecha, las vaporosas en su depâ”œâ”‚sito, con un futuro bastante incierto.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65008400, -0.89472000, '0101000020E6100000C47762D68BA1ECBF91D3D7F335D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15559127050.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15559127050.webp', 'https://www.flickr.com/photos/zaragozaantigua/15559127050/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22786, 'Calle de Santander 1976', 'Imagen capturada en el arranque de la calle de Santander desde la de Escoriaza y Fabro. A la derecha, donde estuviera ubicada la antigua estaciâ”œâ”‚n del ferrocarril de vâ”œÂ¡a estrecha de Cariâ”œâ–’ena-Zaragoza, la manzana delimitada por las calles de Asturias y de Cariâ”œâ–’ena, con los bloques finalizados de los nâ”œâ•‘meros 4 y 6, y el resto en construcciâ”œâ”‚n, o en trâ”œÃ­nsito hacia el derribo, como el chaflâ”œÃ­n de primer plano a la derecha. Al fondo, la moderna plaza de Roma. La ancha calzada para circulaciâ”œâ”‚n motorizada determina el espacio resultante y algunos vehâ”œÂ¡culos, incluso, ocupan la acera aparcados temporalmente en la acera de la izquierda. A la derecha, una soleada cabina telefâ”œâ”‚nica. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38497478261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38497478261.webp', 'https://www.flickr.com/photos/zaragozaantigua/38497478261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22843, 'Calle Anselmo Clavâ”œÂ® 1989', 'Demoliciâ”œâ”‚n completa de un edificio de viviendas de 6 plantas, de estructura mixta hormigâ”œâ”‚n y madera, en el chaflâ”œÃ­n de la calle Anselmo Clavâ”œÂ® con la calle Madre Sacramento.', 1989, 1989, 1989, 'Anos 80', 'DELICIAS', 41.65077300, -0.89351800, '0101000020E6100000FE648C0FB397ECBF560F98874CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15108149056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15108149056.webp', 'https://www.flickr.com/photos/zaragozaantigua/15108149056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22984, 'El Portillo aâ”œâ–’os 90', 'Vista aâ”œÂ®rea de la zona de Zaragoza alrededor de la estaciâ”œâ”‚n del Portillo. Fuente: viajesferroviarios.blogspot.com.es/2015/01/la-revolucion-...', 1990, 1990, 1999, 'Anos 90', 'DELICIAS', 41.65077600, -0.89416200, '0101000020E6100000336E6AA0F99CECBFC782C2A04CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19259886222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19259886222.webp', 'https://www.flickr.com/photos/zaragozaantigua/19259886222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23155, 'Calle Asturias 2009', 'Foto: Juan Carlos Arcos. Construcciâ”œâ”‚n de la Escuela Infantil Municipal El Andâ”œÂ®n, en la calle de San Pedro Arbuâ”œÂ®s 4. La imagen muestra la fachada recayente a la calle de Asturias. Este equipamiento pâ”œâ•‘blico del barrio de Las Delicias fue inaugurado en 2010. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'DELICIAS', 41.65019300, -0.89565600, '0101000020E6100000EAEA8EC536A9ECBF488B338639D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32352330903.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32352330903.webp', 'https://www.flickr.com/photos/zaragozaantigua/32352330903/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23184, 'El Portillo c.2000', 'El tren diurno "Râ”œÂ¡o Aragâ”œâ”‚n" Madrid-Jaca parte desde la estaciâ”œâ”‚n de Zaragoza-El Portillo tras el preceptivo cambio de la locomotora elâ”œÂ®ctrica que lo traccionâ”œâ”‚ hasta aquâ”œÂ¡ por la diesel 319.3 de la imagen, debido a la ausencia de catenaria desde Tardienta. Este servicio convencional desapareciâ”œâ”‚ en diciembre de 2003 como otros tantos como consecuencia de la entrada en servicio la Alta Velocidad Espaâ”œâ–’ola. Esta locomotora fue vendida a la Repâ”œâ•‘blica Argentina en 2009.', 2000, 2000, 2000, 'Siglo XXI', 'DELICIAS', 41.65083700, -0.89426900, '0101000020E6100000B4739A05DA9DECBF6D0377A04ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51046375371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51046375371.webp', 'https://www.flickr.com/photos/zaragozaantigua/51046375371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23318, 'Vista Campo Sepulcro c.1967', 'Panorama de las instalaciones de la Estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro. Los edificios centrales de la Estaciâ”œâ”‚n quedan empequeâ”œâ–’ecidos ante el impresionante Depâ”œâ”‚sito de Locomotoras. Ademâ”œÃ­s, talleres, aguadas, almacenes, viviendas... A la izquierda, el enorme complejo industrial de Carde y Escoriaza. Un poco mâ”œÃ­s al fondo, el Paso a Nivel de Delicias. A la derecha, al fondo, la chimenea de Averly. La imagen ha sido tomada desde la azotea del nâ”¬â•‘ 27 de la calle Alselmo Clavâ”œÂ® (la sombra que se proyecta), por aquel entonces el â”œâ•‘nico edificio de gran altura en toda esa parte de la calle.', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65050000, -0.89364700, '0101000020E61000007364E597C198ECBF2506819543D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14787761130.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14787761130.webp', 'https://www.flickr.com/photos/zaragozaantigua/14787761130/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23970, 'Jardâ”œÂ¡n de Invierno 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Mayo 1966. Imagen de una simpâ”œÃ­tica reuniâ”œâ”‚n-encuentro de la Delegaciâ”œâ”‚n Nacional del Frente de Juventudes (organizaciâ”œâ”‚n juvenil del franquismo) en el Parque Primo de Rivera, en el precioso Jardâ”œÂ¡n de Invierno.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63172600, -0.89277800, '0101000020E610000041D3122BA391ECBF3604C765DCD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097672174.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097672174.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097672174/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23322, 'Estaciâ”œâ”‚n de Cariâ”œâ–’ena c.1900', 'Principios Siglo XX. Colecciâ”œâ”‚n Gerardo Alcaâ”œâ–’iz. La Estaciâ”œâ”‚n de Cariâ”œâ–’ena se inaugurâ”œâ”‚ en 1887, muy cerca de la de Campo Sepulcro. En la imagen, al fondo, las traseras del edificio de la Estaciâ”œâ”‚n, cuyos andenes quedaban recayentes hacia el otro lado. En la vâ”œÂ¡a, el tranvâ”œÂ¡a M-3, habilitado para transporte de mercancâ”œÂ¡as, desde esta Estaciâ”œâ”‚n, por la red tranviaria de la ciudad. La Estaciâ”œâ”‚n de Cariâ”œâ–’ena se ubicaba en lo que ahora es comienzo de la calle Santander. Fue clausurada en 1933, y desmantelado el tendido. El edificio de la estaciâ”œâ”‚n serâ”œÂ¡a derribado a principios de los aâ”œâ–’os 50.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14955731386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14955731386.webp', 'https://www.flickr.com/photos/zaragozaantigua/14955731386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23323, 'Campo Sepulcro 1966', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1966. Imagen tomada desde la pasarela peatonal sobre el mar de vâ”œÂ¡as de la Estaciâ”œâ”‚n de Campo Sepulcro, encauzado hacia la Avenida Goya. Al fondo, a la izquierda, el edificio central de la Estaciâ”œâ”‚n. A la izquierda, el depâ”œâ”‚sito de locomotoras. Escoriaza y Fabro queda a la izquierda, donde la fâ”œÃ­brica Orâ”œâ•‘s; Anselmo Clavâ”œÂ®, a la derecha.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64917000, -0.89409800, '0101000020E61000008368AD68739CECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15237567832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15237567832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15237567832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23325, 'Campo Sepulcro 1912', 'Despedida de tropas coloniales en la Estaciâ”œâ”‚n Campo Sepulcro, con direcciâ”œâ”‚n al norte de â”œÃ¼frica, a pelear en la Guerra del Rif.', 1912, 1912, 1912, 'Anos 10', 'DELICIAS', 41.65103300, -0.89411400, '0101000020E6100000EFA99CF6949CECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15458669657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15458669657.webp', 'https://www.flickr.com/photos/zaragozaantigua/15458669657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23329, 'Campo Sepulcro c.1965', 'Locomotora de vapor Compound De Glehn fabricada en Alemania en 1902, en servicio para la MZA, capturada un poco antes de llegar a la estaciâ”œâ”‚n de Campo Sepulcro. Al fondo, Talleres Mercier, en la avenida de Josâ”œÂ® Anselmo Clavâ”œÂ®. Fuente visual: Foto J.B. Snell, en image.slidesharecdn.com/', 1965, 1965, 1965, 'Anos 60', 'DELICIAS', 41.65103300, -0.89411400, '0101000020E6100000EFA99CF6949CECBFF2CEA10C55D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20524912229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20524912229.webp', 'https://www.flickr.com/photos/zaragozaantigua/20524912229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23333, 'Estaciâ”œâ”‚n de Cariâ”œâ–’ena 1887', '"Tren oficial de la inauguraciâ”œâ”‚n" de la nueva estaciâ”œâ”‚n del ferrocarril de Zaragoza a Cariâ”œâ–’ena, el 10 de agosto de 1887. Al fondo, el edificio central de la Estaciâ”œâ”‚n, en el entorno de Campo del Sepulcro, en una zona luego denominada "barrio de Cariâ”œâ–’ena". Esta lâ”œÂ¡nea fue clausurada y desmantelada en 1933 al entrar en servicio la nueva lâ”œÂ¡nea Zaragoza- Teruel-Valencia.', 1887, 1887, 1887, 'Siglo XIX', 'DELICIAS', 41.64879300, -0.89449500, '0101000020E6100000C8EF6DFAB39FECBFD66F26A60BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25190810155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25190810155.webp', 'https://www.flickr.com/photos/zaragozaantigua/25190810155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23335, 'Campo Sepulcro 1961', 'Imagen capturada desde el pretil del mar de vâ”œÂ¡as ferroviarias, que hacia la izquierda se ensanchaba progresivamente hasta llegar a la estaciâ”œâ”‚n Campo Sepulcro. Al otro lado de la zanja, Anselmo Clavâ”œÂ®, y al fondo, el antiguo edificio de la Casa de Convalecientes, que desde finales de los aâ”œâ–’os cincuenta estaba ocupado por el Colegio Politâ”œÂ®cnico Nuestra Seâ”œâ–’ora del Pilar. Fuente visual: Archivo Municipal de Zaragoza', 1961, 1961, 1961, 'Anos 60', 'DELICIAS', 41.64917000, -0.89409800, '0101000020E61000008368AD68739CECBFACC5A70018D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30091576485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30091576485.webp', 'https://www.flickr.com/photos/zaragozaantigua/30091576485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23340, 'Campo Sepulcro 1967', 'Imagen capturada en el mar de vâ”œÂ¡as de la antigua estaciâ”œâ”‚n de Campo Sepulcro, centrada en dos locomotoras vaporosas allâ”œÂ¡ estacionadas, la primera, de la serie 240-4000, y la segunda, de la serie 241-4000 (ambas, numeraciâ”œâ”‚n RENFE). Al fondo, la avenida Anselmo Clavâ”œÂ®, y el reconocible edificio chaflanero con la calle Madre Sacramento, frente al cuartel de la Policâ”œÂ¡a Armada. A la izquierda, remates de las viviendas militares recayentes a la calle General Mayandâ”œÂ¡a y el paseo de Mâ”¬Â¬ Agustâ”œÂ¡n. Fuente visual: foto Graham T.V. Stacey, en www.spanishrailway.com/', 1967, 1967, 1967, 'Anos 60', 'DELICIAS', 41.65009400, -0.89398900, '0101000020E6100000D57ABFD18E9BECBFB5A9BA4736D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31956847385.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31956847385.webp', 'https://www.flickr.com/photos/zaragozaantigua/31956847385/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23345, 'Campo Sepulcro 1911', 'Imagen capturada desde el mar de vâ”œÂ¡as de la estaciâ”œâ”‚n de Campo Sepulcro de la zanja, o trinchera, y vâ”œÂ¡a â”œâ•‘nica del ferrocarril MZA en direcciâ”œâ”‚n a Barcelona, asâ”œÂ¡ como de los nuevos pasos elevados tendidos sobre ella, siendo el de primer plano el que conducâ”œÂ¡a hacia la derecha al ingreso principal a la estaciâ”œâ”‚n de ferrocarril de Cariâ”œâ–’ena, y los siguientes en el entorno del cruce de la carretera de Zaragoza a Valencia por Teruel. Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'DELICIAS', 41.64889100, -0.89394600, '0101000020E6100000037B4CA4349BECBF99D53BDC0ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39010644140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39010644140.webp', 'https://www.flickr.com/photos/zaragozaantigua/39010644140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24172, 'Pasarela Avenida de Goya 1966', 'AYUNTAMIENTO DE ZARAGOZA/Sancho Ramo, Gerardo/Abril 1966. Desde la Estaciâ”œâ”‚n de Campo Sepulcro y hasta el Paseo de Teruel, donde terminaba la Avenida de Goya, la trinchera del ferrocarril en direcciâ”œâ”‚n a Barcelona seguâ”œÂ¡a al aire, sin cubrir. Una pasarela metâ”œÃ­lica salvaba esa contingencia. Hacia la derecha, sucesivamente se abren reconocibles las calles de Santander, Tarragona-Burgos, Paseo de Teruel, y S. Antonio Marâ”œÂ¡a Claret. En ese punto la Avenida de Goya comienza una peraltada curva hacia la izquierda, en la que se perfila el Corazâ”œâ”‚n de Marâ”œÂ¡a (parroquia catâ”œâ”‚lica). El lado izquierdo de la Avenida estaba menos urbanizado, y hoy sâ”œâ”‚lo perdura el reciente edificio de 10 plantas que chaflanea la calle Câ”œÃ­novas. Justo a la derecha, en primer tâ”œÂ®rmino, donde arranca la calle Santander, desde 1887 y hasta 1933 estuvo activa la Estaciâ”œâ”‚n de tren de vâ”œÂ¡a estrecha de Cariâ”œâ–’ena. Abandonada la lâ”œÂ¡nea ese aâ”œâ–’o, con la entrada en funcionamiento de la lâ”œÂ¡nea de Caminreal, su recorrido por la ciudad fue pronto urbanizado, y el edificio de la estaciâ”œâ”‚n piqueteado en 1940. La paralela calle Cariâ”œâ–’ena recuerda su existencia. En la actualidad, en este punto comienza el espacio de la Glorieta de los Zagrâ”œÂ¡es, confluencia de Anselmo Clavâ”œÂ®, Escoriaza y Fabro, y Goya.', 1966, 1966, 1966, 'Anos 60', 'DELICIAS', 41.64883300, -0.89395800, '0101000020E610000014ECBFCE4D9BECBF65C8B1F50CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849306291.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849306291.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849306291/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24255, 'Calle de Pamplona 1937', 'Familiar imagen de Gustavo Freudenthal Neuhaus, fotâ”œâ”‚grafo retirado y excâ”œâ”‚nsul del Imperio Alemâ”œÃ­n y de la Repâ”œâ•‘blica de Alemania, junto a su nieta Marâ”œÂ¡a Rosario ("Charito") Freudenthal Royo posando con dos perrillos en los jardines de su "hotelito" sito en la calle de Pamplona nâ”¬â•‘ 5 (actual de Joaquâ”œÂ¡n Orâ”œâ•‘s), barrio de La Romareda.', 1937, 1937, 1937, 'Anos 30', 'DELICIAS', 41.65055700, -0.89585700, '0101000020E6100000C5909C4CDCAAECBF8997A77345D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51780064118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51780064118.webp', 'https://www.flickr.com/photos/zaragozaantigua/51780064118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25871, 'Calle Tarragona 2013', 'Entrada al local del nâ”œâ•‘mero 14 de la calle de Tarragona, que fuera ocupado por el cine Salamanca, cuyo voladizo se conserva. Al fondo, la calle de Salamanca.', 2013, 2013, 2013, 'Siglo XXI', 'DELICIAS', 41.64835300, -0.89569900, '0101000020E6100000BCEA01F390A9ECBFBAA1293BFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54388763531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54388763531.webp', 'https://www.flickr.com/photos/zaragozaantigua/54388763531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26061, 'Barrio de Cariâ”œâ–’ena c.1925', 'Imagen capturada desde la altura de las antiguas naves de carpinterâ”œÂ¡a y general de montaje de los Talleres de Carde y Escoriaza, con una interesante vista panorâ”œÃ­mica del que fuera original Barrio de Cariâ”œâ–’ena o de la Romareda. En primer tâ”œÂ®rmino, naves de los talleres de herrerâ”œÂ¡a y montaje, y oficinas de la referida empresa, denominada Material Mâ”œâ”‚vil y Construcciones desde 1920. Detrâ”œÃ­s, el singular barrio de Cariâ”œâ–’ena, con las traseras de las viviendas unifamiliares vertebradas por el cruce de las calles de San Pedro y de Pamplona, y el murete perimetral del mar de vâ”œÂ¡as la estaciâ”œâ”‚n de ferrocarril de Campo Sepulcro. A la derecha, torrecillas de la que fuera fâ”œÃ­brica de chocolares de Orâ”œâ•‘s, y algo mâ”œÃ­s hacia la derecha, fachada principal de la interesante Casa de Convalecientes. Las chimeneas del centro de la imagen corresponden con el gran complejo fabril de Talleres Mercier. Al fondo, poderoso torreâ”œâ”‚n cuadrangular de la Facultad de Medicina y Ciencias; hacia la izquierda, rotunda presencia del convento-colegio de las madres Adoratrices Esclavas del Santâ”œÂ¡simo y de la Caridad, en la calle de Hernâ”œÃ­n Cortâ”œÂ®s esquinero con la calle de la Venerable Madre Sacramento. Cierran la panorâ”œÃ­mica, mâ”œÃ­s a la izquierda, las emergentes torrecillas de la iglesia parroquial de Santa Engracia.', 1925, 1925, 1925, 'Anos 20', 'DELICIAS', 41.65034000, -0.89605000, '0101000020E6100000EA95B20C71ACECBFECA353573ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48997388177.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48997388177.webp', 'https://www.flickr.com/photos/zaragozaantigua/48997388177/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22149, 'Av. de Navarra 1958', 'Imagen capturada en la antigua carretera de Logroâ”œâ–’o, redenominada avenida de Navarra, y centrada en la tranviaria unidad nâ”¬â•‘ 160 dirigiâ”œÂ®ndose al final de la lâ”œÂ¡nea 16 &quot;Portazgo de San Lamberto&quot;, cuyo tendido estaba trazado en el lado de los impares de la avenida. Este &quot;Topolino&quot; serâ”œÂ¡a desguazado en 1972. El disperso entorno edilicio de la â”œÂ®poca posiblemente sea el de las inmediaciones a la calle del Arzobispo Soldevila (a la derecha, fuera de plano). Fuente visual: Josâ”œÂ® Marâ”œÂ¡a Valero Suâ”œÃ­rez, Centenario del tranvâ”œÂ¡a elâ”œÂ®ctrico. Zaragoza, 1902-2002.', 1958, 1958, 1958, 'Anos 50', 'DELICIAS', 41.65502400, -0.90353800, '0101000020E6100000162F1686C8E9ECBF2C0C91D3D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27481278687.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27481278687.webp', 'https://www.flickr.com/photos/zaragozaantigua/27481278687/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22152, 'Av. de Navarra 1959', 'Vista aâ”œÂ®rea de la avenida de Navarra y su entorno. Al fondo, el râ”œÂ¡o Ebro y el barrio de La Almozara. En el centro, la Estaciâ”œâ”‚n de Caminreal y las naves de Transportes Ochoa. A la derecha, el Cuartel de Ferrocarriles y el Mercado de Pescados. Abajo, el Castillo Palomar. Fuente visual: Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65734400, -0.91386200, '0101000020E610000030D461855B3EEDBF651C23D923D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28323489712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28323489712.webp', 'https://www.flickr.com/photos/zaragozaantigua/28323489712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22160, 'Avenida de Navarra 1959', 'Vista aâ”œÂ®rea de la avenida de Navarra y su entorno, con el edificio circular del Mercado de Pescados en el centro. A la derecha, estaciâ”œâ”‚n de Caminreal. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1959, 1959, 1959, 'Anos 50', 'DELICIAS', 41.65598800, -0.90651300, '0101000020E61000005DC30C8D2702EDBFC3482F6AF7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30549378343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30549378343.webp', 'https://www.flickr.com/photos/zaragozaantigua/30549378343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22233, 'Avenida de Madrid c.1955', 'Imagen capturada en el arranque de la calle de Ramâ”œâ”‚n de Campoamor, esquina con la avenida de Madrid, y centrada en la composiciâ”œâ”‚n tranviaria formada por el coche nâ”¬â•‘ 65 (antiguo nâ”¬â•‘ 72 transformado) y el remolque nâ”¬â•‘ 89, en servicio en la lâ”œÂ¡nea 5. Torrero-Delicias, a punto de girar hacia nuestra izquierda para curvear la calle de Campoamor e incorporarse luego nuevamente a la avenida de Madrid, donde la plaza de Huesca, para retomar el trayecto de esta lâ”œÂ¡nea de vuelta hasta Torrero. A la derecha de la imagen, la composiciâ”œâ”‚n coche nâ”¬â•‘ 82 + remolque nâ”¬â•‘ 78 (posiblemente), en servicio en la misma lâ”œÂ¡nea, encaminados hacia Torrero. Tras ellos, el inmueble del nâ”¬â•‘ 165 de la avenida de Madrid, inmediato al arranque de la calle de Las Delicias, y gran solar donde pocos aâ”œâ–’os despuâ”œÂ®s se construirâ”œÂ¡a el inmueble del nâ”¬â•‘ 161-163 de la avenida, esquinero con la calle de Don Pedro de Luna.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65312200, -0.90600700, '0101000020E61000006A4E5E6402FEECBF29266F8099D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50173250413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50173250413.webp', 'https://www.flickr.com/photos/zaragozaantigua/50173250413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22324, 'Avenida de Madrid 1969', 'Imagen de la composiciâ”œâ”‚n motor-remolque 109+109 de la lâ”œÂ¡nea 5 del tranvâ”œÂ¡a "Venecia-Delicias" en la Avenida de Madrid, a punto de llegar a la plaza de Huesca (hasta 1962, plaza de Rocasolano). A la derecha, se abre la calle de Nâ”¬Â¬ Sâ”¬Â¬ de Bonaria. A la izquierda, un poco mâ”œÃ­s adelante, la calle D. Pedro de Luna. Los edificios que aparecen en la imagen han sufrido una curiosa inversiâ”œâ”‚n: los mâ”œÃ­s altos, hoy son como miniaturas, comparados con los gigantes que han surgido sobre las ruinas de las parcelas que parecen mâ”œÃ­s desvalidas. Esta lâ”œÂ¡nea tranviaria, dos aâ”œâ–’os despuâ”œÂ®s, serâ”œÂ¡a clausurada. Fuente visual: Archivo Municipal. Gerardo Sancho. 1969', 1969, 1969, 1969, 'Anos 60', 'DELICIAS', 41.65337800, -0.90512700, '0101000020E61000003E40F7E5CCF6ECBF83F6EAE3A1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16089084439.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16089084439.webp', 'https://www.flickr.com/photos/zaragozaantigua/16089084439/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22459, 'Los Sâ”œÂ¡rex 1968', 'Participantes en un partido de fâ”œâ•‘tbol amistoso celebrado en 1968 en el campo de fâ”œâ•‘tbol de la estaciâ”œâ”‚n de Caminreal, en Las Delicias (al fondo). Los equipos enfrentados estaban formados por un combinado de hostelerâ”œÂ¡a y por empleados del Gran Hotel. Entre los fotografiados posan los componentes del grupo musical Los Sâ”œÂ¡rex. Como madrina de la ceremonia, en el centro, Elba Montalvo, cantante del grupo cubano Los Rivero. Algunos de los que aparecen en la imagen son destacados hosteleros de Zaragoza. Fuente: Heraldo de Aragâ”œâ”‚n.', 1968, 1968, 1968, 'Anos 60', 'DELICIAS', 41.65713200, -0.90927300, '0101000020E61000008A58C4B0C318EDBFD993C0E61CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31909037883.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31909037883.webp', 'https://www.flickr.com/photos/zaragozaantigua/31909037883/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22507, 'Colonia Tudor 1962', 'Imagen de la Colonia Tudor finalmente realizada en empinado terreno entre la avenida de Navarra y el castillo Palomar, que queda detrâ”œÃ­s. El proyecto original, de 1942, era mucho mâ”œÃ­s ambicioso y constaba de viviendas de varios tipos para capataces y empleados y para obreros, aunque no fue llevado a cabo. Este proyecto sâ”œÂ¡ desarrollado veinte aâ”œâ–’os despuâ”œÂ®s constaba de los cinco bloques que aparecen en la fotografâ”œÂ¡a. En los aâ”œâ–’os noventa estas viviendas fueron derribadas y la zona reurbanizada.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65582300, -0.91480400, '0101000020E6100000DEFFC7091346EDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50874022983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50874022983.webp', 'https://www.flickr.com/photos/zaragozaantigua/50874022983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22520, 'Colonia Tudor 1962', 'Imagen de la Colonia Tudor ubicada en empinado terreno entre la avenida de Navarra y el castillo Palomar, que queda justo detrâ”œÃ­s. El proyecto original, de 1942, era mucho mâ”œÃ­s ambicioso y constaba de viviendas de varios tipos para capataces, empleados y obreros de esta empresa, aunque no fue llevado a cabo. El proyecto finalmente desarrollado veinte aâ”œâ–’os despuâ”œÂ®s constaba de sâ”œâ”‚lo cinco bloques. Treinta aâ”œâ–’os despuâ”œÂ®s esta colonia fue derribada y la zona reurbanizada.', 1962, 1962, 1962, 'Anos 60', 'DELICIAS', 41.65582300, -0.91480400, '0101000020E6100000DEFFC7091346EDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54139500585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54139500585.webp', 'https://www.flickr.com/photos/zaragozaantigua/54139500585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22615, 'Av. de Madrid 1976', 'Imagen de los antiguos edificios que esquinaban la Avenida de Madrid con la calle Delicias, luego derribados para levantar otros mâ”œÃ­s higiâ”œÂ®nicos, modernos y altos. A la izquierda extrema, el nâ”¬â•‘ 4 de la calle Delicias (1969). A partir de ahâ”œÂ¡, y hasta el bloque del nâ”¬â•‘ 173 de la Av. de Madrid (1970), a la derecha extrema, todos los edificios han desaparecido, llevâ”œÃ­ndose con ellos sus bajos comerciales, como la panaderâ”œÂ¡a "ARPAN" (Delicias nâ”¬â•‘ 2), la "Ferreterâ”œÂ¡a Marqueta", y "Modas Yoana" (Av. Madrid nâ”¬â•‘ 167), unos Gâ”œÂ®neros de Punto, y otro despacho de "Pan y Reposterâ”œÂ¡a" (Av. Madrid nâ”¬â•‘ 169), y una oficina de la Caja de Ahorros (Av. Madrid nâ”¬â•‘ 171). Sâ”œâ”‚lo sobrevive, modernizada, la agencia de la caja-banco, que se ha expandido, como el universo, y ocupa casi todo el espacio de los locales. Quâ”œÂ® cosas. Fuente: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'DELICIAS', 41.65294600, -0.90614600, '0101000020E6100000C3D66CE525FFECBFEA060ABC93D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19202659722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19202659722.webp', 'https://www.flickr.com/photos/zaragozaantigua/19202659722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22650, 'Calle Don Pedro de Luna c.1975', 'Calle de Don Pedro de Luna, en el barrio de Las Delicias de Zaragoza, vista desde la avenida de Madrid. Fuente: www.facebook.com/photo.php?fbid=853713991317894&set=g...', 1975, 1975, 1975, 'Anos 70', 'DELICIAS', 41.65322600, -0.90548100, '0101000020E6100000B0C7444AB3F9ECBFCD72D9E89CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21086358078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21086358078.webp', 'https://www.flickr.com/photos/zaragozaantigua/21086358078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22672, 'Calle del Requetâ”œÂ® Navarro 1979', 'Calle del Requetâ”œÂ® Navarro, desde 1979 de Rioja, en una vista de su arranque desde la avenida de Madrid. Centra la imagen el edificio de la Casa del Barrio, antigua fâ”œÃ­brica de galletas que en los aâ”œâ–’os 50 fuera Patâ”œÂ¡n Baile, en el nâ”¬â•‘ 219-219 dupdo. de la avenida, luego derribado. Detrâ”œÃ­s, la calle de Croacia, moderno vial que marcaba tendencia respecto a la traza viaria por venir. A la izquierda, edificio de la Compaâ”œâ–’â”œÂ¡a Telefâ”œâ”‚nica construido en 1972.', 1979, 1979, 1979, 'Anos 70', 'DELICIAS', 41.65221500, -0.91038500, '0101000020E6100000529B38B9DF21EDBFF67AF7C77BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24173708189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24173708189.webp', 'https://www.flickr.com/photos/zaragozaantigua/24173708189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22716, 'Avenida de Madrid, 1974', 'En 1902 fueron abiertas la "Escuelas Nacionales del Castillo", como primer colegio de niâ”œâ–’as y niâ”œâ–’os del que habrâ”œÂ¡a de ser barrio de Delicias, en la entonces carretera de Madrid a Francia, luego avenida de Delicias. En 1935 los escolares fueron reubicados en los nuevos centros construidos durante la Segunda Repâ”œâ•‘blica, y el edificio fue reutilizado como estafeta de correos. A partir de 1939 recuperâ”œâ”‚ sus funciones como colegio, y en 1945 fue redenominado "Escuela Nacional Emilio Moreno Calvete", hasta mediados los aâ”œâ–’os 70. En la dâ”œÂ®cada de los 90, en un nuevo edificio sobre el solar del antiguo derribado fue inaugurado el actual "CEIP Emilio Moreno Calvete". En la imagen, captura del antiguo edificio colegial, sito en el nâ”¬â•‘ 145 de la avenida de Madrid. A su derecha, inmediato, quedaba el antiguo Cine Espaâ”œâ–’a, luego Delicias. Fuente visual: Foto Pilar Borobio, incluida en la exposiciâ”œâ”‚n "Escuelas y escolares en Delicias, 1900-2000", Centro Câ”œÂ¡vico Esquinas del Psiquiâ”œÃ­trico.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65346100, -0.90415000, '0101000020E610000074B515FBCBEEECBF111B2C9CA4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29931566602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29931566602.webp', 'https://www.flickr.com/photos/zaragozaantigua/29931566602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22821, 'Monsalud 1974', 'Inâ”œÂ®dita imagen capturada desde la altura de uno de los modernos bloques de viviendas de la calle "E" (desde 1978 calle de Ramâ”œâ”‚n J. Sender) del polâ”œÂ¡gono 40 Monsalud y centrada en las reciâ”œÂ®n inauguradas instalaciones de â”œÃ¼greda Automâ”œâ”‚vil en esta perifâ”œÂ®rica zona entre la Vâ”œÂ¡a de la Hispanidad y la avenida de Navarra. Centra la escena el gran garaje-aparcamiento para un centenar de autobuses, ademâ”œÃ­s de un concesionario para exposiciâ”œâ”‚n y venta de vehâ”œÂ¡culos Mercedes Benz y DKW. Fue diseâ”œâ–’ado por el arquitecto Josâ”œÂ® Beltrâ”œÃ­n Navarro, y a la inauguraciâ”œâ”‚n con bendiciâ”œâ”‚n previa asistieron Moisâ”œÂ®s Calvo Pardo, presidente-gerente de la empresa, y Mariano Horno Liria, alcalde. Al fondo y a la izquierda, bloques en construcciâ”œâ”‚n en el entorno de la calle "G" del polâ”œÂ¡gono (actual nâ”¬â•‘ 3 de la calle de Biarritz), y al otro lado de la avenida de Navarra las instalaciones de la Tudor.', 1974, 1974, 1974, 'Anos 70', 'DELICIAS', 41.65665700, -0.91886000, '0101000020E61000002C4833164D67EDBF41D829560DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51633883347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51633883347.webp', 'https://www.flickr.com/photos/zaragozaantigua/51633883347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22831, 'Vâ”œÂ¡a Universitas 1985', 'La ciudad va creciendo y devorando su pasado. En el cruce de la avenida Madrid con vâ”œÂ¡a Universitas (edificio de Telefâ”œâ”‚nica en primer plano a la izquierda) aâ”œâ•‘n quedaban algunas casas con corral. Pero ya no.', 1985, 1985, 1985, 'Anos 80', 'DELICIAS', 41.65199200, -0.91013700, '0101000020E61000004A253CA1D71FEDBF77A04E7974D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701998757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701998757.webp', 'https://www.flickr.com/photos/zaragozaantigua/14701998757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22834, 'Cuartel Las Delicias c.1987', 'Acuartelamiento ferroviario Las Delicias, en la avenida de Navarra. Ocupado por la Compaâ”œâ–’â”œÂ¡a de Ferrocarriles, fue derribado en 2004.', 1987, 1987, 1987, 'Anos 80', 'DELICIAS', 41.65564900, -0.90749600, '0101000020E6100000AF06280D350AEDBFDA53724EECD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754547999.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754547999.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754547999/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23056, 'Calle del Capitâ”œÃ­n Pina 1994', 'Imagen capturada en el tramo del paseo de Calanda delimitado por las transversales calles de Graus y de Bolivia, y centrado en el cartel anunciador de la construcciâ”œâ”‚n de un garaje subterrâ”œÃ­neo que conservarâ”œÂ¡a la denominaciâ”œâ”‚n franquista de este vial (calle del Capitâ”œÃ­n Pina, antes calle Pinos) cuyo ancho aspecto era resultado del previo derribo de las parcelas occidentales de esta calle. Este proyecto de ensanchamiento ya habâ”œÂ¡a sido perfilado (entre la avenida de Madrid y la calle de Domingo Ram) en un Plan Especial aprobado en 1973 que no tuvo desarrollo posterior. De resultas de esta intervenciâ”œâ”‚n, el paseo se extiende actualmente desde la avenida de Navarra y hasta la calle de la Duquesa de Villahermosa.', 1994, 1994, 1994, 'Anos 90', 'DELICIAS', 41.65156700, -0.90362500, '0101000020E6100000D122DBF97EEAECBF9013268C66D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50449704672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50449704672.webp', 'https://www.flickr.com/photos/zaragozaantigua/50449704672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23140, 'Barrio del AVE 2006', 'Avance del proyecto de urbanizaciâ”œâ”‚n del nuevo barrio del AVE, presentado en mayo de 2006 y diseâ”œâ–’ado por el arquitecto Eduardo Leira. Segâ”œâ•‘n â”œÂ®l, el paseo de la Estaciâ”œâ”‚n serâ”œÂ¡a "el nuevo paseo de la Independencia". La plaza de la Estaciâ”œâ”‚n (luego denominada de El Periâ”œâ”‚dico de Aragâ”œâ”‚n) serâ”œÂ¡a como "el Rockefeller Center de Nueva York". El presidente de Aragâ”œâ”‚n, Marcelino Iglesias, considerâ”œâ”‚ que era "el mayor impulso nunca dado a esta ciudad". De las nuevas edificaciones, mostradas en color marrâ”œâ”‚n, la â”œâ•‘nica realizada en 2017 es el Centro de Especialidades Inocencio Jimâ”œÂ®nez del Servicio Aragonâ”œÂ®s de Salud, en la avenida de Navarra 78, inaugurado en febrero de 2015. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'DELICIAS', 41.66025800, -0.91682600, '0101000020E61000007DEBC37AA356EDBF10768A5583D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31830351741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31830351741.webp', 'https://www.flickr.com/photos/zaragozaantigua/31830351741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23189, 'Plaza de Huesca 2010', 'Foto Pedro Zapater Delgado, 2010. Surtidor de gasâ”œâ”‚leo en estado de abandono, situado en la plaza de Huesca de Zaragoza hasta su retirada en 2014. Fue instalado en 1960 y dejâ”œâ”‚ de prestar servicio dos dâ”œÂ®cadas despuâ”œÂ®s. Fuente: www.heraldo.es/noticias/zaragoza/un_surtidor_olvidado_las...', 2010, 2010, 2010, 'Siglo XXI', 'DELICIAS', 41.65315300, -0.90630800, '0101000020E6100000274D83A27900EDBF64247B849AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19244621146.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19244621146.webp', 'https://www.flickr.com/photos/zaragozaantigua/19244621146/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23436, 'Castillo de Palomar 1960', 'Finca con casa de campo en forma de castillo, estaba situada en la actual finca del Parque del Castillo Palomar en el barrio de Delicias y estuvo en propiedad privada y en pie hasta la dâ”œÂ®cada de los aâ”œâ–’os 60, aunque sus ruinas y cimientos se pudieron contemplar hasta que toda aquella zona y ya siendo propiedad municipal se convirtiâ”œâ”‚ en parque. Fuente : eszaragoza.blogspot.com.es/', 1960, 1960, 1960, 'Anos 60', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14700702280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14700702280.webp', 'https://www.flickr.com/photos/zaragozaantigua/14700702280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23443, 'Castillo de Palomar c.1955', '"Colegio Rosa Arjâ”œâ”‚. Clase de Gimnasia en el Castillo Palomar". Este Colegio Pâ”œâ•‘blico estaba en la calle San Antonio Abad, y para ir al patio recorrâ”œÂ¡an medio kilâ”œâ”‚metro hasta llegar al entorno del "Castillo Palomar", una finca de la familia Palomar en la que se habâ”œÂ¡an regalado una casa con apariencia de castillo, en una propiedad que llegaba desde la Avenida de Navarra hasta la Carretera de los Enlaces. Imagen de niâ”œâ–’as jugando, con el Castillo Palomar de fondo, tras los pinos. En la actualidad aquâ”œÂ¡ hay un parque pâ”œâ•‘blico de algo mâ”œÃ­s de 55 Ha. de extensiâ”œâ”‚n, y todo un nuevo barrio: Monsalud.', 1955, 1955, 1955, 'Anos 50', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14945922706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14945922706.webp', 'https://www.flickr.com/photos/zaragozaantigua/14945922706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23469, 'Castillo de Palomar c.1929', 'Imagen de la que fuera original casa de Narciso Palomar y Cebriâ”œÃ­n y de Rafaela Mendâ”œÂ¡vil y Fâ”œâ•‘rida construida entre 1882 y 1920 en el alto de Monsalud dominando una enorme finca que en el momento de realizar esta fotografâ”œÂ¡a era propiedad de Eustoquia Caballero y Castillejo. A pesar de que Narciso Palomar falleciâ”œâ”‚ en 1885 y no vio terminada la gran casa, â”œÂ®sta conservarâ”œÂ¡a su nombre desde entonces, llegando esa denominaciâ”œâ”‚n hasta nuestros dâ”œÂ¡as. La captura ha sido realizada desde el sur de la enorme propiedad, junto al ascendente camino hasta la gran casa construida en bizarras formas historicistas y mudâ”œÂ®jares sobre un alto que se elevaba casi cien metros respecto de su entorno, visible por ello desde mucha distancia, tal que los antiguos castillos medievales. Al fondo sobresalen los montes de Juslibol por encima de los muros perimetrales del recinto. Fuente visual: Colecciâ”œâ”‚n Josâ”œÂ® Luis Cintora.', 1929, 1929, 1929, 'Anos 20', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30997518928.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30997518928.webp', 'https://www.flickr.com/photos/zaragozaantigua/30997518928/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23477, 'Castillo de Palomar 1943', 'Imagen capturada en el entorno del Castillo Palomar, en la periferia del barrio de Delicias-Terminillo, frente a la estaciâ”œâ”‚n de ferrocarril de Caminreal, a la cota 223.5. La fachada principal de ingreso al castillo hace de telâ”œâ”‚n de fondo a un invernal posado donde destaca un sargento, luciendo el caracterâ”œÂ¡stico capote castrense de la â”œÂ®poca. Fuente visual: www.todocoleccion.net/', 1943, 1943, 1943, 'Anos 40', 'DELICIAS', 41.65582300, -0.91205700, '0101000020E6100000D9CF6229922FEDBF787B1002F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33602265582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33602265582.webp', 'https://www.flickr.com/photos/zaragozaantigua/33602265582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23695, 'Cooperativa de San Antonio 1914', 'La primera cooperativa de casas baratas de Zaragoza fue la "Cooperativa de San Antonio" (abril 1913), para la que el arquitecto Teodoro Râ”œÂ¡os proyectâ”œâ”‚ 40 viviendas unifamiliares en las inmediaciones de la carretera de Navarra. Estas casas se destinaban a obreros y empleados de poco sueldo, que pagarâ”œÂ¡an mensualidades hasta convertirse en propietarios de la casa. En 1917 se hizo una ampliaciâ”œâ”‚n que llegarâ”œÂ¡a hasta la carretera de Madrid por la calle del Arzobispo (luego, Arzobispo Soldevila). En la imagen, vial central en torno al que se ordenaban las Casas Baratas. Cada dos ventanas, una casa (piso superior, dos habitaciones; piso inferior, patio, "water-closset", comedor, cocina, cuarto amplio). Al fondo, la carretera de Navarra, o de Logroâ”œâ–’o. Fuente visual: www.facebook.com/photo.php?fbid=855742017781758&set=g... Fuente textual: Marâ”œÂ¡a Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial en la capital aragonesa entre 1875-1936, IFC, 2004', 1914, 1914, 1914, 'Anos 10', 'DELICIAS', 41.65466900, -0.90383500, '0101000020E6100000795DBF6037ECECBF3E5A9C31CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15380674223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15380674223.webp', 'https://www.flickr.com/photos/zaragozaantigua/15380674223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23701, 'Calle de Antonio Fleta 1964', 'De todas las abundantes acequias que como una red se extendâ”œÂ¡an por Zaragoza, esta imagen nos lleva al barrio de Delicias, al cruce de la calle Antonio Fleta (antes, de Miguel Fleta), con la de Nâ”¬Â¬ Sâ”¬Â¬ de Bonaria (por donde circula el camiâ”œâ”‚n), desde la que una acequia bajaba por toda la calle San Antonio Abad, la cruzaba medio al aire, y luego se bifuncaba, yendo un riego hasta la plaza de Huesca, y otra seguâ”œÂ¡a en paralelo a la antigua carretera de Madrid durante un buen tramo. Esta imagen de las acequias al aire era recurrente en la Zaragoza de la periferia. Fotografâ”œÂ¡a datada gracias a la amable aportaciâ”œâ”‚n de Fernando Benito. Fuente visual: Archivo Municipal, Gerardo Sancho Ramo, 1964.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65400400, -0.90515900, '0101000020E610000016C3D50110F7ECBF02BA2F67B6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18194641035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18194641035.webp', 'https://www.flickr.com/photos/zaragozaantigua/18194641035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23703, 'Plaza de Huesca 1980', 'La antigua plaza de Gregorio Rocasolano contaba desde 1960 con un surtidor de gasâ”œâ”‚leo que aparece en la foto. Fue desmontado en 2014. Fuente: Zaragoza barrio a barrio, 1981.', 1980, 1980, 1980, 'Anos 80', 'DELICIAS', 41.65315300, -0.90630800, '0101000020E6100000274D83A27900EDBF64247B849AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18649882333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18649882333.webp', 'https://www.flickr.com/photos/zaragozaantigua/18649882333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23706, 'Calle de Graus 1978', 'Aspecto de la cuesta de la calle de Graus del barrio de Las Delicias, con la calle de Don Pedro de Luna a la espalda y la del Doctor Pâ”œÂ®rez Serrano al fondo. A la derecha, bares desaparecidos, como El Pinar, câ”œÂ®lebre por sus patatas bravas. Fuente: www.rafaelcastillejo.com', 1978, 1978, 1978, 'Anos 70', 'DELICIAS', 41.65189400, -0.90481700, '0101000020E6100000B4ACFBC742F4ECBFB43A394371D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21109557458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21109557458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21109557458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
