INSERT INTO public.photos VALUES (23720, 'Av. de Madrid 1964', 'Imagen de la avenida de Madrid, a la altura de la reciente calle denominada Garcilaso de la Vega (izquierda), cuando dos unidades de la serie 40 (nâ”¬â•‘ 44, y nâ”¬â•‘ 47) en servicio en la lâ”œÂ¡nea 14 (Oliver), se estâ”œÃ­n cruzando en el desvâ”œÂ¡o de mitad de trayecto, entre la plaza de Huesca (antigua de Rocasolano, al fondo de la imagen), y el Enlace de Carreteras. Era curiosa la denominaciâ”œâ”‚n de esta lâ”œÂ¡nea, porque durante casi veinte aâ”œâ–’os dio servicio al barrio de Oliver, sin llegar a entrar en â”œÂ®l. Estas dos unidades tranviarias fueron retiradas de la circulaciâ”œâ”‚n y desguazadas al poco tiempo. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1964, 1964, 1964, 'Anos 60', 'DELICIAS', 41.65151300, -0.91285100, '0101000020E610000061DEE34C1336EDBF9DF529C764D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31500011746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31500011746.webp', 'https://www.flickr.com/photos/zaragozaantigua/31500011746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
